let mvuInitialized = false;
let mvuInitPromise: Promise<void> | null = null;

/** 确保 MVU 全局已就绪（角色卡内置 MVU + iframe 环境） */
export async function ensureMvuInitialized(): Promise<void> {
  if (mvuInitialized) return;
  if (mvuInitPromise) {
    console.info('ℹ️ [variableReader] MVU 初始化已在进行中，等待结果…');
    return mvuInitPromise;
  }

  console.info('🔍 [variableReader] 正在初始化 MVU…');

  mvuInitPromise = (async () => {
    try {
      await waitGlobalInitialized('Mvu');
      mvuInitialized = true;
      console.info('✅ [variableReader] MVU 初始化完成');
    } catch (error) {
      console.warn('⚠️ [variableReader] 等待 MVU 初始化失败，后续仍尝试同步读取', error);
      mvuInitialized = true;
    }
  })();

  return mvuInitPromise;
}

/** `stat_data` 是否有实质内容 */
export function hasStatDataContent(stat_data: unknown): boolean {
  if (!stat_data || typeof stat_data !== 'object' || Array.isArray(stat_data)) return false;
  return Object.keys(stat_data as object).length > 0;
}

/**
 * 判断是否为 MVU 标量元组 `[值, "描述"]`。
 * 若首项也是 string，则不自动当作元组（避免把 `["张三","李四"]` 这类双名列表误拆）。
 */
function isMvuScalarTuple(v: unknown[]): boolean {
  if (v.length < 2 || typeof v[1] !== 'string') return false;
  return typeof v[0] !== 'string';
}

function unwrapMvuScalar(value: unknown): unknown {
  if (Array.isArray(value) && isMvuScalarTuple(value)) {
    return unwrapMvuScalar(value[0]);
  }
  return value;
}

/**
 * 深度解包 `stat_data` 中的 MVU 元组（对象递归；数组仅在「非元组」时逐项处理，保留 `在场NPC` 等 string[]）。
 */
export function deepUnwrapMvuStatData(value: unknown): unknown {
  const u = unwrapMvuScalar(value);
  if (u === null || typeof u !== 'object') return u;
  if (Array.isArray(u)) {
    if (isMvuScalarTuple(u)) {
      return deepUnwrapMvuStatData(u[0]);
    }
    return u.map(el => deepUnwrapMvuStatData(el));
  }
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(u)) {
    out[k] = deepUnwrapMvuStatData(v);
  }
  return out;
}

/**
 * 从嵌套对象按 `a.b.c` 取值，支持 MVU 元组 `[值, "描述"]`（仅非 string 首项时解包，与 `deepUnwrapMvuStatData` 一致）。
 */
export function pick<T extends Value>(obj: unknown, path: string, fallback: T): T {
  if (!obj || typeof obj !== 'object') return fallback;
  const parts = path.split('.').filter(Boolean);
  let cur: unknown = obj;

  // pick 专用：当 fallback 期望是 string 时，允许解包 `[string, "描述"]`，避免把 `['A','B']` 误当作 tuple。
  const unwrapTupleForPick = (value: unknown): unknown => {
    let v = value;
    // 只在 MVU tuple 形态（长度为 2 且第二项为描述字符串）时解包
    while (Array.isArray(v) && v.length === 2 && typeof v[1] === 'string') {
      const allow =
        // fallback 期望 string：允许 `[string, "描述"]`
        typeof fallback === 'string' ||
        // 否则：沿用深度解包的保守规则，避免把字符串列表误拆
        typeof v[0] !== 'string';
      if (!allow) break;
      v = v[0];
    }
    return v;
  };

  for (const p of parts) {
    if (cur === null || cur === undefined) return fallback;

    cur = unwrapTupleForPick(cur);

    if (typeof cur !== 'object' || cur === null) return fallback;
    cur = (cur as Record<string, unknown>)[p];
  }

  cur = unwrapTupleForPick(cur);

  if (cur === undefined || cur === null) return fallback;
  return cur as T;
}

function extractFromMvuData(data: unknown): { stat_data: Record<string, unknown>; display_data?: Record<string, unknown> } | null {
  if (!data || typeof data !== 'object') return null;
  const o = data as Record<string, unknown>;
  const stat = o.stat_data;
  if (!hasStatDataContent(stat)) return null;
  return {
    stat_data: stat as Record<string, unknown>,
    display_data: (o.display_data as Record<string, unknown>) ?? undefined,
  };
}

/** 优先：最新一条 assistant 楼层的 MVU / data */
function tryLatestAssistantPayload(): { stat_data: Record<string, unknown>; display_data?: Record<string, unknown> } | null {
  try {
    const lastId = getLastMessageId();
    const assistantMessages = getChatMessages(`0-${lastId}`, { role: 'assistant', hide_state: 'all' });
    if (!assistantMessages?.length) {
      console.warn('⚠️ [variableReader] 🔍 Step1/2：未找到 assistant 楼层，跳过最新 assistant 回退链');
      return null;
    }
    const latestAssistant = assistantMessages[assistantMessages.length - 1];
    const messageId = latestAssistant.message_id;

    // Step1：最新 assistant 楼层的 MVU（通过 Mvu.getMvuData）
    try {
      console.info(`🔍 [variableReader] Step1：尝试 Mvu.getMvuData(message, ${messageId})`);
      const mvuData = Mvu.getMvuData({ type: 'message', message_id: messageId });
      const ex = extractFromMvuData(mvuData);
      if (ex) {
        console.info(`✅ [variableReader] 自最新 assistant 楼层 #${messageId} 读取 MVU stat_data`);
        return ex;
      }
      console.warn(`⚠️ [variableReader] Step1：Mvu.getMvuData(message, ${messageId}) 的 stat_data 为空对象，继续尝试 data 字段`);
    } catch (e) {
      console.warn(`⚠️ [variableReader] Step1：Mvu.getMvuData(message, ${messageId}) 失败`, e);
    }

    // Step2：备用方案：最新 assistant 楼层的 data 字段（data.stat_data）
    const row = latestAssistant as { data?: Record<string, unknown> };
    const d = row.data;
    if (d && hasStatDataContent(d.stat_data)) {
      console.info(`✅ [variableReader] 自最新 assistant 楼层 #${messageId} 的 data.stat_data 读取`);
      return {
        stat_data: d.stat_data as Record<string, unknown>,
        display_data: d.display_data as Record<string, unknown> | undefined,
      };
    }
    console.warn(`⚠️ [variableReader] Step2：assistant.data.stat_data 无效或为空对象（message #${messageId}），继续尝试 latest 回退`);
  } catch (e) {
    console.warn('⚠️ [variableReader] Step1/2：遍历 assistant 楼层失败', e);
  }
  return null;
}

function tryLatestMessagePayload(): { stat_data: Record<string, unknown>; display_data?: Record<string, unknown> } | null {
  try {
    // Step3：退化方案：从 message_id: 'latest' 读取 MVU
    console.info('🔍 [variableReader] Step3：尝试 Mvu.getMvuData(message, latest)');
    const mvuData = Mvu.getMvuData({ type: 'message', message_id: 'latest' });
    const ex = extractFromMvuData(mvuData);
    if (ex) {
      console.info('✅ [variableReader] 自 Mvu.getMvuData(latest) 读取 stat_data');
      return ex;
    }
    console.warn('⚠️ [variableReader] Step3：Mvu.getMvuData(latest) 的 stat_data 为空对象/无效，继续尝试 getVariables(latest)');
  } catch (e) {
    console.warn('⚠️ [variableReader] Step3：Mvu.getMvuData(latest) 失败', e);
  }

  // Step4：从 latest 获取变量（getVariables fallback）
  try {
    console.info('🔍 [variableReader] Step4：尝试 getVariables(message, latest)');
    const variables = getVariables({ type: 'message', message_id: 'latest' }) as Record<string, unknown> | undefined;
    if (variables && hasStatDataContent(variables.stat_data)) {
      console.info('✅ [variableReader] 自 getVariables(message, latest) 读取 stat_data');
      return {
        stat_data: variables.stat_data as Record<string, unknown>,
        display_data: variables.display_data as Record<string, unknown> | undefined,
      };
    }
    console.warn('⚠️ [variableReader] Step4：getVariables(message, latest) 的 stat_data 无效/为空对象');
  } catch (e) {
    console.warn('⚠️ [variableReader] Step4：getVariables(latest) 失败', e);
  }
  return null;
}

function tryMessageZeroPayload(): { stat_data: Record<string, unknown>; display_data?: Record<string, unknown> } | null {
  try {
    // Step5：从 0 层读取 MVU（初始化数据）
    console.info('🔍 [variableReader] Step5：尝试 Mvu.getMvuData(message, 0)');
    const mvuData = Mvu.getMvuData({ type: 'message', message_id: 0 });
    const ex = extractFromMvuData(mvuData);
    if (ex) {
      console.info('✅ [variableReader] 自 0 层 Mvu.getMvuData 读取 stat_data');
      return ex;
    }
    console.warn('⚠️ [variableReader] Step5：Mvu.getMvuData(0) 的 stat_data 为空对象/无效，继续尝试 getVariables(0)');
  } catch (e) {
    console.warn('⚠️ [variableReader] Step5：Mvu.getMvuData(0) 失败', e);
  }
  try {
    // Step6：0 层变量读取（最终退化）
    console.info('🔍 [variableReader] Step6：尝试 getVariables(message, 0)');
    const variables = getVariables({ type: 'message', message_id: 0 }) as Record<string, unknown> | undefined;
    if (variables && hasStatDataContent(variables.stat_data)) {
      console.info('✅ [variableReader] 自 getVariables(message, 0) 读取 stat_data');
      return {
        stat_data: variables.stat_data as Record<string, unknown>,
        display_data: variables.display_data as Record<string, unknown> | undefined,
      };
    }
    console.warn('⚠️ [variableReader] Step6：getVariables(message, 0) 的 stat_data 无效/为空对象');
  } catch (e) {
    console.warn('⚠️ [variableReader] Step6：getVariables(0) 失败', e);
  }
  return null;
}

function resolveLatestStatDataPayload(): { stat_data: Record<string, unknown>; display_data?: Record<string, unknown> } {
  return (
    tryLatestAssistantPayload() ??
    tryLatestMessagePayload() ??
    tryMessageZeroPayload() ?? { stat_data: {} }
  );
}

function resolveStatDataForMessageId(messageId: number): { stat_data: Record<string, unknown>; display_data?: Record<string, unknown> } {
  try {
    const mvuData = Mvu.getMvuData({ type: 'message', message_id: messageId });
    const ex = extractFromMvuData(mvuData);
    if (ex) return ex;
  } catch {
    /* ignore */
  }
  try {
    const variables = getVariables({ type: 'message', message_id: messageId }) as Record<string, unknown> | undefined;
    if (variables && hasStatDataContent(variables.stat_data)) {
      return {
        stat_data: variables.stat_data as Record<string, unknown>,
        display_data: variables.display_data as Record<string, unknown> | undefined,
      };
    }
  } catch {
    /* ignore */
  }
  return { stat_data: {} };
}

/**
 * 异步读取当前应用於 UI 的 MVU 负载（含多源回退）；会先 `ensureMvuInitialized`。
 * 返回的 `stat_data` 已做 MVU 元组解包，可直接交给 `merge*FromMvu`。
 */
export async function getGameMvuData(): Promise<{
  stat_data: Record<string, unknown>;
  display_data?: Record<string, unknown>;
}> {
  console.info('🔍 [variableReader] getGameMvuData：开始读取游戏 MVU 数据');
  await ensureMvuInitialized();
  const raw = resolveLatestStatDataPayload();

  if (!hasStatDataContent(raw.stat_data)) {
    console.warn('⚠️ [variableReader] getGameMvuData：未读取到有效 stat_data，将返回空对象（用于初始化/降级）');
  } else {
    console.info('✅ [variableReader] getGameMvuData：成功读取有效 stat_data（已进入解包流程）');
  }

  return {
    stat_data: deepUnwrapMvuStatData(raw.stat_data) as Record<string, unknown>,
    display_data: raw.display_data
      ? (deepUnwrapMvuStatData(raw.display_data) as Record<string, unknown>)
      : undefined,
  };
}

/**
 * 读取指定消息楼层的 `stat_data`（与角色卡 `Schema` 根字段一致）。
 * - `message_id: 'latest'`：走「最新 assistant → latest → 0 层」链，并解包 MVU 元组。
 * - 指定数字：只读该楼层 MVU / getVariables。
 */
export function getStatDataFromMessage(messageId: 'latest' | number = 'latest'): unknown {
  let raw: { stat_data: Record<string, unknown>; display_data?: Record<string, unknown> };

  if (messageId === 'latest') {
    raw = resolveLatestStatDataPayload();
  } else {
    raw = resolveStatDataForMessageId(messageId);
  }

  const unwrapped = deepUnwrapMvuStatData(raw.stat_data);
  return unwrapped;
}

export function asMvuStatData(raw: unknown): MvuStatData {
  if (raw !== null && typeof raw === 'object' && !Array.isArray(raw)) {
    return raw as MvuStatData;
  }
  return {};
}

/**
 * 新建楼层时从「上一楼层」拷贝用的完整 MVU 负载（与 `createChatMessages` 的 layer 一致）。
 */
export function getMvuLayerPayloadFromLatestMessage(): {
  stat_data: Record<string, unknown>;
  display_data: Record<string, unknown>;
  delta_data: Record<string, unknown>;
} {
  const fallback = { stat_data: {}, display_data: {}, delta_data: {} };
  try {
    try {
      const mvuData = Mvu.getMvuData({ type: 'message', message_id: 'latest' });
      if (mvuData && typeof mvuData === 'object') {
        const o = mvuData as Record<string, unknown>;
        return {
          stat_data: (deepUnwrapMvuStatData(o.stat_data) as Record<string, unknown>) ?? {},
          display_data: (o.display_data as Record<string, unknown>) ?? {},
          delta_data: (o.delta_data as Record<string, unknown>) ?? {},
        };
      }
    } catch {
      /* fall through */
    }
    const variables = getVariables({ type: 'message', message_id: 'latest' });
    return {
      stat_data: (deepUnwrapMvuStatData(variables?.stat_data) as Record<string, unknown>) ?? {},
      display_data: (variables?.display_data as Record<string, unknown>) ?? {},
      delta_data: (variables?.delta_data as Record<string, unknown>) ?? {},
    };
  } catch {
    return fallback;
  }
}

function summarizeValue(value: unknown): string {
  if (value === null) return 'null';
  if (value === undefined) return 'undefined';
  if (Array.isArray(value)) return `array(len=${value.length})`;
  if (typeof value === 'object') return `object(keys=${Object.keys(value as object).length})`;
  return `${typeof value}(${String(value)})`;
}

/**
 * 从已解包的 `stat_data` 提取与 Zod 根结构对齐的摘要（供调试/变量查看器；字段路径与 `MVU_STAT_TO_UI_MAP` 对应）。
 */
export function pickStatDataUiSnapshot(stat_data: unknown): Record<string, string> {
  if (!stat_data || typeof stat_data !== 'object') return { stat_data: 'invalid' };
  const s = stat_data as Record<string, unknown>;
  const snap: Record<string, string> = {};
  const add = (path: string, label: string) => {
    snap[label] = summarizeValue(pick(s, path, undefined));
  };
  add('孙悟空.头像', '孙悟空.头像→主角头像');
  add('孙悟空.当前状态.当前血量', '当前血量→Character.hp');
  add('孙悟空.当前状态.当前灵力', '当前灵力→Character.mp');
  add('孙悟空.当前状态.增益状态', '增益状态→Character.buffs');
  add('孙悟空.能力面板.最大血量', '最大血量→maxHp');
  add('孙悟空.修为境界', '修为境界→realm');
  add('孙悟空.功法.主修功法', '主修功法→technique / gongfaAvatar');
  add('孙悟空.技能列表', '技能列表→神通');
  add('孙悟空.行囊', '行囊→Inventory');
  add('孙悟空.装备栏', '装备栏→修行法宝区');
  add('孙悟空.队伍', '队伍→HUD队伍');
  add('世界.当前大区', '当前大区→status.region');
  add('世界.当前地点', '当前地点→status.place');
  add('世界.在场NPC', '在场NPC→HUD');
  add('羁绊', '羁绊→羁绊面板');
  add('当前任务', '当前任务→任务面板');
  return snap;
}

/**
 * readYourGameData：读取并按 YourGameData（MVU 根结构）组织输出。
 * - 内部调用 `getGameMvuData`（含 MVU 初始化、多源回退、`deepUnwrapMvuStatData`）
 * - 使用 `pick` 从嵌套结构提取值（支持 MVU 元组 `[值, "描述"]`）
 * - `世界` 拆出 `当前大区` / `当前地点` / `在场NPC`，与 Zod `世界` 对象及底部状态条、HUD 一致
 */
export async function readYourGameData(): Promise<YourGameData> {
  console.info('🔍 [variableReader] readYourGameData：开始');

  const { stat_data } = await getGameMvuData();

  console.info('✅ [variableReader] readYourGameData：getGameMvuData 返回完成，开始 pick 提取');

  const sunWukong = pick<MvuStatData['孙悟空'] | undefined>(stat_data, '孙悟空', undefined);
  console.info(`🔍 [variableReader] pick 孙悟空 → ${summarizeValue(sunWukong)}`);

  const worldRegionRaw = pick<string>(stat_data, '世界.当前大区', '');
  const worldRegion: string | undefined = worldRegionRaw.trim() ? worldRegionRaw : undefined;

  // 使用 '' 作为 fallback：便于 pick 解包 `[string, "描述"]`；空串视为未设置
  const worldCurrentPlaceRaw = pick<string>(stat_data, '世界.当前地点', '');
  const worldCurrentPlace: string | undefined = worldCurrentPlaceRaw.trim() ? worldCurrentPlaceRaw : undefined;

  const worldNpcsPresent = pick<string[] | undefined>(stat_data, '世界.在场NPC', undefined);
  console.info(
    `🔍 [variableReader] pick 世界 → 当前大区 ${summarizeValue(worldRegion)}; 当前地点 ${summarizeValue(worldCurrentPlace)}; 在场NPC ${summarizeValue(worldNpcsPresent)}`,
  );

  const world: MvuStatData['世界'] | undefined =
    worldRegion !== undefined || worldCurrentPlace !== undefined || worldNpcsPresent !== undefined
      ? {
          当前大区: worldRegion,
          当前地点: worldCurrentPlace,
          在场NPC: worldNpcsPresent,
        }
      : undefined;

  const bonds = pick<MvuStatData['羁绊'] | undefined>(stat_data, '羁绊', undefined);
  console.info(`🔍 [variableReader] pick 羁绊 → ${summarizeValue(bonds)}`);

  const quests = pick<MvuStatData['当前任务'] | undefined>(stat_data, '当前任务', undefined);
  console.info(`🔍 [variableReader] pick 当前任务 → ${summarizeValue(quests)}`);

  const out: YourGameData = {
    孙悟空: sunWukong,
    世界: world,
    羁绊: bonds,
    当前任务: quests,
  };

  console.info('✅ [variableReader] readYourGameData：完成输出', {
    孙悟空: summarizeValue(out.孙悟空),
    世界: summarizeValue(out.世界),
    羁绊: summarizeValue(out.羁绊),
    当前任务: summarizeValue(out.当前任务),
    uiSnapshot: pickStatDataUiSnapshot(stat_data),
  });

  return out;
}
