/**
 * 根组件：按聊天是否为空切换 标题 → 开局表单 → 主界面（GameScreen）。
 */

import { useCallback, useEffect, useState } from 'react';
import GameScreen from './components/GameScreen';
import OpeningForm from './components/OpeningForm';
import TitleScreen from './components/TitleScreen';
import {
  createOpeningStoryMessage,
  initializeGameVariables,
  isChatEmptyForOpening,
} from './utils/gameInitializer';
import { isDocumentFullscreen, requestDocumentFullscreen } from './utils/fullscreen';
import type { OpeningFormData } from './types';

/** 与 adventure 模板一致的阶段划分 */
export enum GamePhase {
  LOADING = 'loading',
  TITLE = 'title',
  OPENING = 'opening',
  GAME = 'game',
}

export default function App() {
  const [phase, setPhase] = useState<GamePhase>(GamePhase.LOADING);

  const resolveInitialPhase = useCallback(() => {
    try {
      const empty = isChatEmptyForOpening();
      console.info('📊 [大泼猴] 开局检测', { lastMessageId: getLastMessageId(), empty });
      if (empty) {
        setPhase(GamePhase.TITLE);
      } else {
        setPhase(GamePhase.GAME);
      }
    } catch (error) {
      console.error('❌ [大泼猴] 检测楼层失败，默认进入开局流程', error);
      setPhase(GamePhase.TITLE);
    }
  }, []);

  useEffect(() => {
    resolveInitialPhase();
  }, [resolveInitialPhase]);

  /** 结束载入后自动请求浏览器全屏（部分环境需用户手势，失败仅打日志） */
  useEffect(() => {
    if (phase === GamePhase.LOADING) return;
    const id = window.setTimeout(() => {
      void (async () => {
        if (isDocumentFullscreen()) return;
        try {
          await requestDocumentFullscreen();
          console.info('🖥️ [大泼猴] 载入完成后已进入全屏');
        } catch (error) {
          console.warn('⚠️ [大泼猴] 自动全屏失败', error);
        }
      })();
    }, 100);
    return () => window.clearTimeout(id);
  }, [phase]);

  const handleOpeningSubmit = async (data: OpeningFormData) => {
    console.info('🎮 [大泼猴] 初始化游戏变量…');
    const initOk = await initializeGameVariables(data);
    if (!initOk) {
      console.warn('⚠️ [大泼猴] 初始化游戏变量未完全成功，仍尝试进入游戏');
    }

    console.info('📖 [大泼猴] 创建开局剧情楼层…');
    const storyOk = await createOpeningStoryMessage(data);
    if (!storyOk) {
      console.warn('⚠️ [大泼猴] 创建开局剧情楼层未完全成功，仍进入主界面');
      toastr.error('开局楼层创建失败，请检查酒馆权限或聊天状态', '大泼猴');
    }

    setPhase(GamePhase.GAME);
  };

  if (phase === GamePhase.LOADING) {
    return (
      <div className="fade-in flex min-h-[100dvh] w-full items-center justify-center text-paper/70">
        <p className="pulse-effect text-sm tracking-[0.2em]">载入中…</p>
      </div>
    );
  }

  if (phase === GamePhase.OPENING) {
    return (
      <OpeningForm
        onSubmit={handleOpeningSubmit}
        onBack={() => setPhase(GamePhase.TITLE)}
      />
    );
  }

  if (phase === GamePhase.TITLE) {
    return <TitleScreen onStart={() => setPhase(GamePhase.OPENING)} />;
  }

  return (
    <div
      id="app"
      className="app fade-in flex h-dvh min-h-dvh w-full min-w-0 flex-col overflow-hidden"
    >
      <GameScreen />
    </div>
  );
}
