function normalizeNameKey(name: string): string {
  return name.trim();
}

/** 按名称查默认图（先精确匹配，再忽略大小写匹配） */
export function resolveDefaultFabaoAvatarByName(name: string): string | undefined {
  const k = normalizeNameKey(name);
  if (!k) return undefined;
  const direct = DEFAULT_FABAO_AVATAR_BY_NAME[k];
  if (direct) return direct;
  const lower = k.toLowerCase();
  for (const [n, url] of Object.entries(DEFAULT_FABAO_AVATAR_BY_NAME)) {
    if (n.trim().toLowerCase() === lower) return url;
  }
  return undefined;
}
