export function markerKindClasses(kind: MapMarkerKind): { dot: string; glow: string } {
  /** 交互点偏暗、低饱和，避免 emerald/sky 400 类荧光感；光晕减弱以免抢眼 */
  switch (kind) {
    case 'capital':
      return {
        dot: 'bg-gold-muted',
        glow: 'shadow-[0_0_7px_rgba(153,101,21,0.42)]',
      };
    case 'sacred':
      return {
        dot: 'bg-crimson',
        glow: 'shadow-[0_0_7px_rgba(90,10,10,0.38)]',
      };
    case 'wild':
      return {
        dot: 'bg-emerald-800/85',
        glow: 'shadow-[0_0_7px_rgba(6,78,59,0.35)]',
      };
    case 'sea':
      return {
        dot: 'bg-sky-800/90',
        glow: 'shadow-[0_0_7px_rgba(7,89,133,0.36)]',
      };
  }
}
