/**
 * 地貌类型 → 图片 URL
 * 你可以在这里按“森林/平原/深山/雪地/戈壁/沙漠: 链接”继续补全。
 */
export const DEFAULT_TERRAIN_IMAGE_BY_KEY: Record<TerrainKey, string> = {
  森林: 'https://files.catbox.moe/1wapk8.jpg',
  平原: 'https://files.catbox.moe/9h8olp.jpg',
  深山: 'https://files.catbox.moe/pp3ejt.png',
  雪地: 'https://files.catbox.moe/5ze7iw.jpg',
  戈壁: 'https://files.catbox.moe/mlyhtc.jpg',
  沙漠: 'https://files.catbox.moe/t9k4ek.png',
  未知: '',
};

function normalizeText(s: string): string {
  return s.replace(/\s+/g, ' ').trim();
}

function isUnknownPlace(place: string | undefined): boolean {
  if (!place) return true;
  const p = normalizeText(place);
  return !p || p === '未知' || p.toLowerCase() === 'unknown';
}

function normalizeKeyForMap(s: string): string {
  // 为了尽量兼容“全角/半角空格、换行”等输入，做统一 trim+空白压缩
  return normalizeText(s);
}

function tryResolveByExactOrCaseInsensitiveName(placeName: string): string | undefined {
  const key = normalizeKeyForMap(placeName);
  if (!key) return undefined;
  const direct = DEFAULT_PLACE_IMAGE_BY_NAME[key];
  if (direct) return direct;
  const lower = key.toLowerCase();
  for (const [n, url] of Object.entries(DEFAULT_PLACE_IMAGE_BY_NAME)) {
    if (normalizeKeyForMap(n).toLowerCase() === lower) return url;
  }
  return undefined;
}

const TERRAIN_KEYWORDS: Array<{ key: TerrainKey; words: string[] }> = [
  { key: '雪地', words: ['雪', '冰', '寒', '霜', '雪原', '冰原'] },
  { key: '沙漠', words: ['沙漠', '黄沙', '荒漠', '戈沙', '流沙'] },
  { key: '戈壁', words: ['戈壁', '碎石滩', '砾石'] },
  { key: '森林', words: ['森林', '树林', '密林', '林海', '林间', '古林'] },
  { key: '平原', words: ['平原', '草原', '沃野', '大地', '原野'] },
  { key: '深山', words: ['深山', '山谷', '峡谷', '悬崖', '崇山', '险峰', '大山'] },
];

function inferTerrainFromText(texts: string[]): TerrainKey {
  const joined = texts.filter(Boolean).join(' ');
  if (!joined) return '未知';
  const s = joined;
  for (const group of TERRAIN_KEYWORDS) {
    if (group.words.some(w => s.includes(w))) return group.key;
  }
  return '未知';
}

/**
 * 解析“地点图片”并返回用于展示的信息。
 * - 优先：指定地点名（DEFAULT_PLACE_IMAGE_BY_NAME）
 * - 否则：从 place/region 文本推断地貌（DEFAULT_TERRAIN_IMAGE_BY_KEY）
 */
export function resolvePlaceDisplayImage(
  placeName: string | undefined,
  regionName?: string,
): { imageUrl?: string; label: string; terrain: TerrainKey } {
  const label = normalizeText(placeName ?? '');
  const unknown = isUnknownPlace(placeName);

  const direct = !unknown ? tryResolveByExactOrCaseInsensitiveName(placeName || '') : undefined;
  if (direct) {
    return { imageUrl: direct, label: label || '未知地点', terrain: '未知' };
  }

  const terrain = inferTerrainFromText([placeName ?? '', regionName ?? '']);
  const url = DEFAULT_TERRAIN_IMAGE_BY_KEY[terrain];
  return {
    imageUrl: url ? url : undefined,
    label: label || regionName || '未知地点',
    terrain,
  };
}

