/**
 * 全屏 API 封装（标准 + webkit / moz / ms），与 adventure 流程对齐。
 */

type FsDoc = Document & {
  webkitFullscreenElement?: Element | null;
  mozFullScreenElement?: Element | null;
  msFullscreenElement?: Element | null;
  webkitExitFullscreen?: () => Promise<void> | void;
  mozCancelFullScreen?: () => Promise<void> | void;
  msExitFullscreen?: () => Promise<void> | void;
};

type FsElement = HTMLElement & {
  webkitRequestFullscreen?: () => Promise<void> | void;
  mozRequestFullScreen?: () => Promise<void> | void;
  msRequestFullscreen?: () => Promise<void> | void;
};

export function getFullscreenElement(): Element | null {
  const d = document as FsDoc;
  return (
    document.fullscreenElement ??
    d.webkitFullscreenElement ??
    d.mozFullScreenElement ??
    d.msFullscreenElement ??
    null
  );
}

export function isDocumentFullscreen(): boolean {
  return getFullscreenElement() !== null;
}

export async function requestDocumentFullscreen(): Promise<void> {
  const el = document.documentElement as FsElement;
  if (typeof el.requestFullscreen === 'function') {
    await el.requestFullscreen();
    return;
  }
  if (typeof el.webkitRequestFullscreen === 'function') {
    await Promise.resolve(el.webkitRequestFullscreen());
    return;
  }
  if (typeof el.mozRequestFullScreen === 'function') {
    await Promise.resolve(el.mozRequestFullScreen());
    return;
  }
  if (typeof el.msRequestFullscreen === 'function') {
    await Promise.resolve(el.msRequestFullscreen());
    return;
  }
  throw new Error('Fullscreen API unavailable');
}

export async function exitDocumentFullscreen(): Promise<void> {
  const d = document as FsDoc;
  if (typeof document.exitFullscreen === 'function') {
    await document.exitFullscreen();
    return;
  }
  if (typeof d.webkitExitFullscreen === 'function') {
    await Promise.resolve(d.webkitExitFullscreen());
    return;
  }
  if (typeof d.mozCancelFullScreen === 'function') {
    await Promise.resolve(d.mozCancelFullScreen());
    return;
  }
  if (typeof d.msExitFullscreen === 'function') {
    await Promise.resolve(d.msExitFullscreen());
    return;
  }
  throw new Error('Exit fullscreen unavailable');
}

const FULLSCREEN_EVENTS = [
  'fullscreenchange',
  'webkitfullscreenchange',
  'mozfullscreenchange',
  'MSFullscreenChange',
] as const;

/**
 * 订阅全屏变化（覆盖前缀浏览器），返回卸载函数。
 */
export function onFullscreenChange(handler: () => void): () => void {
  for (const type of FULLSCREEN_EVENTS) {
    document.addEventListener(type, handler);
  }
  return () => {
    for (const type of FULLSCREEN_EVENTS) {
      document.removeEventListener(type, handler);
    }
  };
}
