/**
 * 消息解析工具库（大泼猴前端）
 * - 从楼层消息中解析 `<maintext>` / `<option>` / `<sum>` 等；剥离 `<thinking>`、`<redacted_thinking>` 内内容，
 *   避免误解析模型推理块。
 * - 与 adventure 思路一致，并增强：`<正文>`、`<content>`、`<branches>`、`<!-- -->` 注释、`<UpdateVariable>` 等
 *   （见 `parseMaintext` / `finalizeStoryDisplayText`）。
 * - `loadFromLatestMessage`：取最后一条 **assistant**（末楼为 user 时仍用上一条 AI），返回正文、选项、剧情总结 `sum`、任务 `mission` 等。
 */
import { StoryOption, UiMessage } from '../types';

/** 与 `types.StoryOption` 同形，便于对外文档或复制示例中使用 `Option` 命名 */
export type Option = StoryOption;

/** 与 `removeThinkingTags` / `finalizeStoryDisplayText` 共用，避免在 `/.../` 中写反引号导致语法错误 */
const CLOSING_THINK_MARKER = '`' + '</think>' + '`';

export function removeThinkingTags(text: string): string {
  if (!text) return '';
  let cleaned = text.replace(/<thinking>[\s\S]*?<\/thinking>/gi, '');
  /** 不同模型闭合标签不一致，两种都剥 */
  cleaned = cleaned.replace(/<redacted_thinking>[\s\S]*?<\/redacted_thinking>/gi, '');
  cleaned = cleaned.replace(/<think>[\s\S]*?<\/redacted_reasoning>/gi, '');
  /** 部分模型残留推理闭合片段（含 Claude 式闭合标记） */
  cleaned = cleaned.replace(new RegExp(`\\s*${CLOSING_THINK_MARKER}\\s*`, 'g'), '');
  cleaned = cleaned.split(CLOSING_THINK_MARKER).join('');
  cleaned = cleaned.replace(/<\/think>/gi, '');
  cleaned = cleaned.replace(/<\/thinking>/gi, '');
  const thinkingStart = cleaned.search(/<thinking>/i);
  if (thinkingStart !== -1) cleaned = cleaned.slice(0, thinkingStart);
  const thinkStart = cleaned.search(/<think>/i);
  if (thinkStart !== -1) cleaned = cleaned.slice(0, thinkStart);
  return cleaned;
}

/** 全角等异体写法，避免漏删注释 */
function normalizeCommentMarkers(s: string): string {
  return s
    .replace(/\uFF1C\uFF01--/g, '<!--')
    .replace(/--\uFF1E/g, '-->')
    .replace(/\uFF1C!--/g, '<!--');
}

/**
 * 去掉 HTML 风格注释 `<!-- ... -->`（含 emotion_check、dialogue_antThinking 等）。
 * 不用单次正则：注释内若出现 `--`，`[\s\S]*?` 可能提前匹配到中间的 `-->` 导致残留或漏删。
 * 采用自 `<!--` 起查找下一个 `-->` 成对删除；若无闭合则删至文末。
 */
function stripHtmlComments(s: string): string {
  let out = normalizeCommentMarkers(s);
  let prev = '';
  let outer = 0;
  while (out !== prev && outer++ < 30) {
    prev = out;
    let guard = 0;
    while (guard++ < 200) {
      const start = out.indexOf('<!--');
      if (start === -1) break;
      const end = out.indexOf('-->', start + 4);
      if (end === -1) {
        out = out.slice(0, start).trimEnd();
        break;
      }
      out = out.slice(0, start) + out.slice(end + 3);
    }
  }
  return out.replace(/\n{3,}/g, '\n\n').trim();
}

/** 删除仍以 `<!--` 开头的整行（漏网或畸形注释） */
function stripCommentOnlyLines(s: string): string {
  return s
    .split('\n')
    .filter(line => !/^\s*<!--/.test(line))
    .join('\n');
}

/** 剥离剧情展示中不应出现的元数据块（图二、三中的 sum / UpdateVariable / Memory 等） */
function stripKnownMetadataBlocks(s: string): string {
  let t = s;
  const blocks: RegExp[] = [
    /<Memory>[\s\S]*?<\/Memory>/gi,
    /<UpdateVariable>[\s\S]*?<\/UpdateVariable>/gi,
    /<sum>[\s\S]*?<\/sum>/gi,
    /<summary>[\s\S]*?<\/summary>/gi,
    /<branches>[\s\S]*?<\/branches>/gi,
    /<mission>[\s\S]*?<\/mission>/gi,
    /<Analysis>[\s\S]*?<\/Analysis>/gi,
    /<JSONPatch>[\s\S]*?<\/JSONPatch>/gi,
    /<jsonpatch>[\s\S]*?<\/jsonpatch>/gi,
  ];
  for (const re of blocks) t = t.replace(re, '');
  return t.replace(/\n{3,}/g, '\n\n').trim();
}

/**
 * 最终展示用净化：仅保留「图一」类可读叙事，不含 HTML 注释与元数据标签。
 * 在 parseMaintext 末尾统一调用。
 */
export function finalizeStoryDisplayText(s: string): string {
  if (!s.trim()) return '';
  let t = stripKnownMetadataBlocks(s);
  t = stripHtmlComments(t);
  t = stripCommentOnlyLines(t);
  t = stripHtmlComments(t);
  t = t.replace(new RegExp(`\\s*${CLOSING_THINK_MARKER}\\s*`, 'g'), '');
  t = t.split(CLOSING_THINK_MARKER).join('');
  t = t.replace(/\u200B/g, '');
  return t.replace(/\n{3,}/g, '\n\n').trim();
}

/** 从字符串中按最后一个匹配取标签内文本 */
function takeLastTagInner(cleaned: string, tagName: string): string {
  const re = new RegExp(`<${tagName}>([\\s\\S]*?)<\\/${tagName}>`, 'gi');
  const matches = cleaned.match(re);
  if (!matches?.length) return '';
  const last = matches[matches.length - 1].match(new RegExp(`<${tagName}>([\\s\\S]*?)<\\/${tagName}>`, 'i'));
  return (last?.[1] ?? '').trim();
}

/** 提取楼层内 `<sum>…</sum>`（取最后一处），用于读档列表摘要；兼容 `<summary>` */
export function parseSum(message: string): string {
  const cleaned = removeThinkingTags(message);
  const matches = cleaned.match(/<sum>([\s\S]*?)<\/sum>/gi);
  if (matches && matches.length > 0) {
    const last = matches[matches.length - 1].match(/<sum>([\s\S]*?)<\/sum>/i);
    const inner = (last?.[1] ?? '').trim();
    if (inner.length > 0) return stripHtmlComments(inner);
  }
  const summaryMatches = cleaned.match(/<summary>([\s\S]*?)<\/summary>/gi);
  if (summaryMatches && summaryMatches.length > 0) {
    const last = summaryMatches[summaryMatches.length - 1].match(/<summary>([\s\S]*?)<\/summary>/i);
    return stripHtmlComments((last?.[1] ?? '').trim());
  }
  return '';
}

export type AssistantFloorRow = {
  message_id: number;
  maintext: string;
  sum: string;
};

/** 当前聊天中所有 AI 楼层，供阅读模式 / 读档列表使用 */
export function getAssistantFloorsForReadUi(): AssistantFloorRow[] {
  const lastMessageId = getLastMessageId();
  if (lastMessageId < 0) return [];
  const chatMessages = getChatMessages(`0-${lastMessageId}`, { role: 'assistant', hide_state: 'all' });
  return chatMessages.map(m => ({
    message_id: m.message_id,
    maintext: parseMaintext(m.message || ''),
    sum: parseSum(m.message || ''),
  }));
}

export function parseMaintext(message: string): string {
  let cleaned = removeThinkingTags(message);
  /** 先全局剥注释，避免在 `<正文>` 外或标签边界残留 <!-- emotion_check … --> */
  cleaned = stripHtmlComments(cleaned);
  const matches = cleaned.match(/<maintext>([\s\S]*?)<\/maintext>/gi);
  if (matches && matches.length > 0) {
    const last = matches[matches.length - 1].match(/<maintext>([\s\S]*?)<\/maintext>/i);
    const inner = (last?.[1] ?? '').trim();
    if (inner.length > 0) return finalizeStoryDisplayText(inner);
  }
  const contentMatches = cleaned.match(/<content>([\s\S]*?)<\/content>/gi);
  if (contentMatches && contentMatches.length > 0) {
    const last = contentMatches[contentMatches.length - 1].match(/<content>([\s\S]*?)<\/content>/i);
    const inner = (last?.[1] ?? '').trim();
    if (inner.length > 0) return finalizeStoryDisplayText(inner);
  }
  /** 部分模型使用 `<正文>…</正文>` 而非 `<maintext>` */
  const zhengwen = takeLastTagInner(cleaned, '正文');
  if (zhengwen.length > 0) return finalizeStoryDisplayText(zhengwen);

  // 无上述标签：剥掉常见剧情块与结构标签后展示剩余正文
  let remainder = cleaned.replace(/<maintext>[\s\S]*?<\/maintext>/gi, '');
  remainder = remainder.replace(/<content>[\s\S]*?<\/content>/gi, '');
  remainder = remainder.replace(/<正文>[\s\S]*?<\/正文>/gi, '');
  remainder = remainder.replace(/<summary>[\s\S]*?<\/summary>/gi, '');
  remainder = remainder.replace(/<sum>[\s\S]*?<\/sum>/gi, '');
  remainder = remainder.replace(/<branches>[\s\S]*?<\/branches>/gi, '');
  remainder = remainder.replace(/<option>[\s\S]*?<\/option>/gi, '');
  remainder = remainder.replace(/<option\s+id="[^"]+">[\s\S]*?<\/option>/gi, '');
  remainder = remainder.replace(/<UpdateVariable>[\s\S]*?<\/UpdateVariable>/gi, '');
  remainder = remainder.replace(/<mission>[\s\S]*?<\/mission>/gi, '');
  remainder = remainder.replace(/<Memory>[\s\S]*?<\/Memory>/gi, '');
  remainder = remainder.replace(/<Analysis>[\s\S]*?<\/Analysis>/gi, '');
  remainder = remainder.replace(/<JSONPatch>[\s\S]*?<\/JSONPatch>/gi, '');
  remainder = remainder.replace(/<jsonpatch>[\s\S]*?<\/jsonpatch>/gi, '');
  remainder = remainder.trim();
  if (remainder.length > 0) return finalizeStoryDisplayText(remainder);
  return finalizeStoryDisplayText(cleaned.trim());
}

/** 校验模型原始回复是否含合规的剧情块（用于 generate 成功后、写入楼层前） */
export function validateGeneratedStoryFormat(raw: string): { ok: true } | { ok: false; reason: string } {
  const cleaned = removeThinkingTags(raw).trim();
  if (!cleaned) return { ok: false, reason: '模型未返回可见正文' };

  const mainMatch = cleaned.match(/<maintext>([\s\S]*?)<\/maintext>/i);
  const contentMatch = cleaned.match(/<content>([\s\S]*?)<\/content>/i);
  const zhengwenMatch = cleaned.match(/<正文>([\s\S]*?)<\/正文>/i);
  const mainBody = (mainMatch?.[1] ?? '').trim();
  const contentBody = (contentMatch?.[1] ?? '').trim();
  const zhengwenBody = (zhengwenMatch?.[1] ?? '').trim();
  if (!mainBody && !contentBody && !zhengwenBody) {
    // 允许无标签正文：剥离常见标签后的剩余内容也算有效
    const remainder = cleaned
      .replace(/<maintext>[\s\S]*?<\/maintext>/gi, '')
      .replace(/<content>[\s\S]*?<\/content>/gi, '')
      .replace(/<正文>[\s\S]*?<\/正文>/gi, '')
      .replace(/<summary>[\s\S]*?<\/summary>/gi, '')
      .replace(/<branches>[\s\S]*?<\/branches>/gi, '')
      .replace(/<option[\s\S]*?<\/option>/gi, '')
      .replace(/<UpdateVariable>[\s\S]*?<\/UpdateVariable>/gi, '')
      .trim();
    if (!remainder) {
      return {
        ok: false,
        reason: '回复缺少可展示的正文（<maintext>/<content>/<正文> 为空，且无可见内容）',
      };
    }
  }

  const hasIdOptions = /<option\s+id="/i.test(cleaned);
  if (hasIdOptions) {
    const blocks = [...cleaned.matchAll(/<option\s+id="[^"]+">[\s\S]*?<\/option>/gi)];
    if (blocks.length === 0) return { ok: false, reason: '含有 <option id= 但未形成合法 <option id="…">…</option> 块' };
  } else {
    // <option> 允许缺失：界面会自动补“继续”
  }

  return { ok: true };
}

export function parseOptions(message: string): StoryOption[] {
  const cleaned = removeThinkingTags(message);
  const optionsWithId: StoryOption[] = [];
  const withIdRegex = /<option id="([^"]+)">([\s\S]*?)<\/option>/gi;
  let match: RegExpExecArray | null = withIdRegex.exec(cleaned);
  while (match) {
    optionsWithId.push({ id: match[1], text: match[2].trim() });
    match = withIdRegex.exec(cleaned);
  }
  if (optionsWithId.length > 0) return optionsWithId;

  /** 部分模型把选项包在 `<branches>…</branches>` 内，再单独扫一遍 */
  const branchesBlock = cleaned.match(/<branches>([\s\S]*?)<\/branches>/i)?.[1];
  if (branchesBlock) {
    const fromBranches: StoryOption[] = [];
    const br = /<option id="([^"]+)">([\s\S]*?)<\/option>/gi;
    let m: RegExpExecArray | null = br.exec(branchesBlock);
    while (m) {
      fromBranches.push({ id: m[1], text: m[2].trim() });
      m = br.exec(branchesBlock);
    }
    if (fromBranches.length > 0) return fromBranches;
  }

  const plainOption = cleaned.match(/<option>([\s\S]*?)<\/option>/i)?.[1]?.trim();
  if (!plainOption) return [];

  const lines = plainOption
    .split('\n')
    .map(line => line.trim())
    .filter(Boolean);

  /** `A.` 起头新选项；后续不以字母点开头的行并入当前选项（多行描述） */
  const letterLineStart = /^[A-Z]\.\s*/;
  const hasLetterPrefix = lines.some(line => letterLineStart.test(line));

  if (hasLetterPrefix) {
    const out: StoryOption[] = [];
    let current: string[] = [];
    for (const line of lines) {
      if (letterLineStart.test(line)) {
        if (current.length > 0) {
          const block = current.join('\n');
          const id = block.match(/^([A-Z])\./)?.[1] ?? String.fromCharCode(65 + out.length);
          out.push({
            id,
            text: block.replace(/^[A-Z]\.\s*/, '').trim(),
          });
          current = [];
        }
        current.push(line);
      } else if (current.length > 0) {
        current.push(line);
      }
    }
    if (current.length > 0) {
      const block = current.join('\n');
      const id = block.match(/^([A-Z])\./)?.[1] ?? String.fromCharCode(65 + out.length);
      out.push({
        id,
        text: block.replace(/^[A-Z]\.\s*/, '').trim(),
      });
    }
    return out;
  }

  return lines.map((line, index) => ({
    id: String.fromCharCode(65 + index),
    text: line,
  }));
}

export function getUiMessagesFromChat(): UiMessage[] {
  const lastMessageId = getLastMessageId();
  if (lastMessageId < 0) return [];
  // `all`：含被酒馆标记为隐藏的楼层，否则部分 AI 楼可能被 `unhidden` 筛掉导致前端看不到生成内容
  const chatMessages = getChatMessages(`0-${lastMessageId}`, { hide_state: 'all' });
  return chatMessages.map((message, idx) => {
    if (message.role === 'assistant') {
      let paired_user_message_id: number | undefined;
      for (let j = idx - 1; j >= 0; j--) {
        if (chatMessages[j].role === 'user') {
          paired_user_message_id = chatMessages[j].message_id;
          break;
        }
      }
      return {
        role: 'assistant' as const,
        content: parseMaintext(message.message || ''),
        message_id: message.message_id,
        full_raw: message.message || '',
        paired_user_message_id,
      };
    }
    return {
      role: message.role,
      content: (message.message || '').trim(),
      message_id: message.message_id,
    };
  });
}

/**
 * 取聊天中**最后一条** assistant 楼层（若当前最后一楼是 user，则取上一条 assistant）。
 */
function getLatestAssistantMessageRow(): ChatMessage | null {
  const atEnd = getChatMessages(-1, { role: 'assistant', hide_state: 'all' });
  if (atEnd?.length) return atEnd[0];

  const lastId = getLastMessageId();
  if (lastId < 0) return null;
  const allAssistant = getChatMessages(`0-${lastId}`, { role: 'assistant', hide_state: 'all' });
  if (!allAssistant.length) return null;
  return allAssistant[allAssistant.length - 1];
}

function findPairedUserMessageId(assistantMessageId: number): number | undefined {
  const lastId = getLastMessageId();
  if (lastId < 0) return undefined;
  const all = getChatMessages(`0-${lastId}`, { hide_state: 'all' });
  const idx = all.findIndex(m => m.message_id === assistantMessageId);
  if (idx <= 0) return undefined;
  for (let j = idx - 1; j >= 0; j--) {
    if (all[j].role === 'user') return all[j].message_id;
  }
  return undefined;
}

/** 从消息中解析 `<mission>…</mission>`（取最后一处） */
/** 长按编辑时识别的剧情正文块（与 parseMaintext 优先级一致） */
export type EditableStoryTag = 'maintext' | '正文' | 'content';

export function detectEditableStoryBlock(
  fullMessage: string,
): { tag: EditableStoryTag; inner: string } | null {
  const m = fullMessage.match(/<maintext>([\s\S]*?)<\/maintext>/i);
  if (m) return { tag: 'maintext', inner: m[1].trim() };
  const z = fullMessage.match(/<正文>([\s\S]*?)<\/正文>/i);
  if (z) return { tag: '正文', inner: z[1].trim() };
  const c = fullMessage.match(/<content>([\s\S]*?)<\/content>/i);
  if (c) return { tag: 'content', inner: c[1].trim() };
  return null;
}

export function replaceEditableStoryBlock(
  fullMessage: string,
  tag: EditableStoryTag,
  newInner: string,
): string {
  switch (tag) {
    case 'maintext':
      return fullMessage.replace(/<maintext>[\s\S]*?<\/maintext>/i, `<maintext>${newInner}</maintext>`);
    case '正文':
      return fullMessage.replace(/<正文>[\s\S]*?<\/正文>/i, `<正文>${newInner}</正文>`);
    case 'content':
      return fullMessage.replace(/<content>[\s\S]*?<\/content>/i, `<content>${newInner}</content>`);
    default:
      return fullMessage;
  }
}

export function parseMission(message: string): string {
  const cleaned = removeThinkingTags(message);
  const matches = cleaned.match(/<mission>([\s\S]*?)<\/mission>/gi);
  if (matches && matches.length > 0) {
    const last = matches[matches.length - 1].match(/<mission>([\s\S]*?)<\/mission>/i);
    return (last?.[1] ?? '').trim();
  }
  return '';
}

/**
 * 从最新 assistant 楼层解析 `<maintext>`、`<option>`、`<sum>` 等（与指南 `loadFromLatestMessage` 一致）。
 * 用于主界面「正文框」与选项区单一数据源。
 */
export function loadFromLatestMessage(): {
  maintext: string;
  options: StoryOption[];
  sum: string;
  messageId?: number;
  userMessageId?: number;
  fullMessage?: string;
  mission: string;
} {
  try {
    const latest = getLatestAssistantMessageRow();
    if (!latest) {
      return { maintext: '', options: [], sum: '', mission: '' };
    }

    const messageContent = latest.message || '';
    const maintext = parseMaintext(messageContent);
    const options = parseOptions(messageContent);
    const sum = parseSum(messageContent);
    const mission = parseMission(messageContent);
    const userMessageId = findPairedUserMessageId(latest.message_id);

    return {
      maintext,
      options,
      sum,
      messageId: latest.message_id,
      userMessageId,
      fullMessage: messageContent,
      mission,
    };
  } catch (error) {
    console.error('❌ [messageParser] loadFromLatestMessage 失败:', error);
    return { maintext: '', options: [], sum: '', mission: '' };
  }
}

export function getLatestStoryOptions(): StoryOption[] {
  return loadFromLatestMessage().options;
}
