/**
 * 功法 / 神通技能 的**内置默认头像**（外链图片 URL）。
 *
 * 键名与以下之一一致即可：
 * - `孙悟空.功法.主修功法.名称`（主修功法卡片）
 * - `孙悟空.技能列表` 的对象键（神通技能列表）
 *
 * 展示顺序见 `resolveGongfaDisplayAvatar`。
 */

export const DEFAULT_GONGFA_AVATAR_BY_NAME: Record<string, string> = {
  大品天仙诀: 'https://files.catbox.moe/6f0n8w.jpg',
  八九玄功: 'https://files.catbox.moe/7yf2c1.jpg',
  九转炼形诀: 'https://files.catbox.moe/livgpi.jpg',
  黄庭内景经: 'https://files.catbox.moe/7rec5o.jpg',
  琉璃仙体: 'https://files.catbox.moe/ciwfgc.jpg',
  诛仙剑诀: 'https://files.catbox.moe/bj5ods.jpg',
  大梦心经: 'https://files.catbox.moe/y1s6vc.jpg',
  大日如来真经: 'https://files.catbox.moe/xuux02.bmp',
  太清道德玄经: 'https://files.catbox.moe/o6v23z.bmp',
  河图洛书: 'https://files.catbox.moe/w443xv.bmp',
  太清神霄雷法: 'https://files.catbox.moe/qbulxj.bmp',
};

/** 未在 `DEFAULT_GONGFA_AVATAR_BY_NAME` 中指定时的随机兜底图标 URL 列表 */
const FALLBACK_GONGFA_AVATAR_URLS: string[] = [
  'https://files.catbox.moe/iz8xc9.jpg',
  'https://files.catbox.moe/2akku8.jpg',
  'https://files.catbox.moe/8sesue.jpg',
  'https://files.catbox.moe/9i5605.jpg',
  'https://files.catbox.moe/9i5605.jpg',
  'https://files.catbox.moe/82zd4n.jpg',
  'https://files.catbox.moe/oemszx.jpg',
  'https://files.catbox.moe/w3boko.jpg',
  'https://files.catbox.moe/0mezpw.jpg',
];

function normalizeNameKey(name: string): string {
  return name.trim();
}

function hashToInt(input: string): number {
  // 简单可用的字符串 hash，保证同名稳定映射到同一个兜底图（避免频繁随机导致闪烁）
  let h = 0;
  for (let i = 0; i < input.length; i++) {
    h = (h * 31 + input.charCodeAt(i)) >>> 0;
  }
  return h;
}

/** 按名称查默认图（先精确匹配，再忽略大小写匹配） */
export function resolveDefaultGongfaAvatarByName(name: string): string | undefined {
  const k = normalizeNameKey(name);
  if (!k || k === '无') return undefined;
  const direct = DEFAULT_GONGFA_AVATAR_BY_NAME[k];
  if (direct) return direct;
  const lower = k.toLowerCase();
  for (const [n, url] of Object.entries(DEFAULT_GONGFA_AVATAR_BY_NAME)) {
    if (n.trim().toLowerCase() === lower) return url;
  }
  if (FALLBACK_GONGFA_AVATAR_URLS.length === 0) return undefined;
  const idx = hashToInt(k.toLowerCase()) % FALLBACK_GONGFA_AVATAR_URLS.length;
  return FALLBACK_GONGFA_AVATAR_URLS[idx];
}

/**
 * 主修功法或神通条目的展示用头像。
 * 优先级：`mvuAvatar`（MVU「头像」字段）→ 本表按名称。
 */
export function resolveGongfaDisplayAvatar(
  techniqueOrSkillName: string | undefined,
  mvuAvatar?: string | undefined,
): string | undefined {
  const url = mvuAvatar?.trim();
  if (url) return url;
  if (!techniqueOrSkillName?.trim()) return undefined;
  return resolveDefaultGongfaAvatarByName(techniqueOrSkillName);
}
