function normalizeKey(s: string): string {
  // 与 `utils/placeImage.ts` 保持一致：兼容全角/半角空格、换行等输入差异
  return s.replace(/\s+/g, ' ').trim();
}

export function isProbablyUsableRemoteAvatarUrl(url: string | undefined): boolean {
  if (!url) return false;
  const v = url.trim();
  if (!v) return false;

  // 一些持久化数据可能会把 `.` 等字符做了 URL 编码，导致 includes 匹配不到。
  // 尝试 decode 一次，尽可能识别 `127.0.0.1` / `localhost`。
  let decoded = v;
  try {
    decoded = decodeURIComponent(v);
  } catch {
    // ignore
  }

  // 过滤明显的本机地址：对方无法访问，会导致坏图标。
  // 例：`http://127.0.0.1:8000/%E6%A5%A8%E5%A9%B5...`
  if (decoded.includes('127.0.0.1') || decoded.includes('localhost')) return false;

  // 本地上传用 FileReader 生成的 dataURL，肯定可用（也能跨发布页面展示）。
  if (v.startsWith('data:image/')) return true;

  // 其它情况：只要不是空且不是明显本机地址，一般都“可能能用”。
  return true;
}

/** 按单个名称或 id 查内置图 */
export function resolveDefaultBondAvatarByName(nameOrId: string): string | undefined {
  const k = normalizeKey(nameOrId);
  if (!k) return undefined;

  const direct = DEFAULT_BOND_AVATAR_BY_NAME[k];
  if (direct) return direct;

  const lower = k.toLowerCase();
  for (const [n, url] of Object.entries(DEFAULT_BOND_AVATAR_BY_NAME)) {
    if (normalizeKey(n).toLowerCase() === lower) return url;
  }
  return undefined;
}

/**
 * 最终展示用头像 URL（右侧栏、羁绊面板等统一调用）
 * 逻辑参考地图 `placeImage.ts`：只依赖内置表按名称解析（精确/忽略大小写匹配），
 * 不优先使用 MVU/持久化头像，避免跨用户复用不可直链的外部地址。
 */
export function resolveBondDisplayAvatar(
  bond: Bond,
  persistedById: Record<string, string>,
): string | undefined {
  void persistedById; // 现在不再把持久化头像作为优先来源（逻辑与地图一致）

  // 按名称解析：先 name 再 id
  return resolveDefaultBondAvatarByName(bond.name) || resolveDefaultBondAvatarByName(bond.id);
}
