import { locations } from './data/journeyLocations';
import { markerKindClasses, type MapMarker } from './mapData';

const SOURCE_WIDTH = 1000;
const SOURCE_HEIGHT = 562;

function mapRegion(region: 'East' | 'West' | 'South' | 'North'): MapMarker['region'] {
  switch (region) {
    case 'East':
      return '东胜神州';
    case 'West':
      return '西牛贺洲';
    case 'South':
      return '南瞻部洲';
    case 'North':
      return '北俱芦洲';
  }
}

function mapKind(name: string, description: string): MapMarker['kind'] {
  const text = `${name} ${description}`;
  if (/(海|河|湖|潭|江|龙宫|归墟|弱水|码头)/.test(text)) return 'sea';
  if (/(寺|观|宫|殿|天门|洞天|灵山|禅院|庙|塔)/.test(text)) return 'sacred';
  if (/(城|国|镇|关|庄|都)/.test(text)) return 'capital';
  return 'wild';
}

function toPct(value: number, max: number): number {
  return Math.max(0, Math.min(100, Number(((value / max) * 100).toFixed(2))));
}

export const WORLD_MAP_MARKERS: MapMarker[] = locations.map(loc => {
  const [xRaw, yRaw] = loc.coords.split(',');
  const x = Number(xRaw);
  const y = Number(yRaw);
  return {
    id: `journey-${loc.id}`,
    name: loc.name,
    blurb: loc.description,
    leftPct: toPct(Number.isFinite(x) ? x : 0, SOURCE_WIDTH),
    topPct: toPct(Number.isFinite(y) ? y : 0, SOURCE_HEIGHT),
    kind: mapKind(loc.name, loc.description),
    region: mapRegion(loc.region),
  };
});

export { markerKindClasses, type MapMarker };

