import type { Item } from '../types';
import { resolveDefaultFabaoAvatarByName } from './fabaoAvatar';

/**
 * 行囊格子默认头像：键为 **MVU 行囊里的物品名**（与 `stat_data.孙悟空.行囊` 的键一致），值为图片 URL（可 https 或 data:）。
 * 用户用相机自定义过的物品、或 MVU 里写了「头像」的条目，会覆盖这里的默认值。
 */
export const DEFAULT_INVENTORY_ITEM_AVATAR_BY_NAME: Record<string, string> = {
  如意金箍棒: 'https://files.catbox.moe/t6o3zg.jpg',
  /** 与「如意金箍棒」同图，便于行囊键名略写时使用 */
  金箍棒: 'https://files.catbox.moe/t6o3zg.jpg',
};

function normalizeNameKey(name: string): string {
  return name.trim();
}

/** 按名称查默认图（先精确匹配，再忽略大小写匹配） */
export function resolveDefaultInventoryAvatarByName(name: string): string | undefined {
  const k = normalizeNameKey(name);
  if (!k) return undefined;
  const direct = DEFAULT_INVENTORY_ITEM_AVATAR_BY_NAME[k];
  if (direct) return direct;
  const lower = k.toLowerCase();
  for (const [n, url] of Object.entries(DEFAULT_INVENTORY_ITEM_AVATAR_BY_NAME)) {
    if (n.trim().toLowerCase() === lower) return url;
  }
  return undefined;
}

/**
 * 行囊格子最终展示用头像 URL。
 * 优先级：界面持久化映射（按 id）→ MVU 条目「头像」→ 行囊通用名映射 →
 * 法宝/神兵名映射（与 `fabaoAvatar.ts` 一致；不限 `accessory`，便于钉耙、剑等作装备类型时也能命中）。
 */
export function resolveInventoryItemDisplayAvatar(
  item: Item,
  persistedById: Record<string, string>,
): string | undefined {
  const persisted = persistedById[item.id];
  if (persisted) return persisted;
  const mvu = item.mvuAvatar?.trim();
  if (mvu) return mvu;
  const fromInventory = resolveDefaultInventoryAvatarByName(item.name);
  if (fromInventory) return fromInventory;
  return resolveDefaultFabaoAvatarByName(item.name);
}
