/**
 * 统一游戏请求：选项 / 自定义输入、流式预览、剥除 thinking、标签重组、MVU 解析、写入楼层。
 */
import { RequestData, StoryOption } from '../types';
import {
  parseMaintext,
  parseOptions,
  parseSum,
  removeThinkingTags,
  validateGeneratedStoryFormat,
} from './messageParser';
import { checkAndUpdateChronicleByAssistantMessage } from './chronicleUpdater';
import { getMvuLayerPayloadFromLatestMessage } from './variableReader';

export type StoryRequestCallbacks = {
  onDisableOptions?: () => void;
  onShowGenerating?: () => void;
  onHideGenerating?: () => void;
  onEnableOptions?: () => void;
  onError?: (error: string) => void;
  onRefreshStory?: () => void;
  /** 流式：当前完整文本中解析出的 &lt;maintext&gt; 内部预览 */
  onStreamingUpdate?: (text: string) => void;
  /** MVU 解析成功后刷新界面侧变量展示（可选） */
  onRefreshVariables?: () => void;
  /** 自定义输入发送失败并回滚用户楼后，把该文本写回输入框 */
  onRestoreUserInput?: (text: string) => void;
};

/** 与流式回调共用，剥除 &lt;thinking&gt; 等 */
export function removeThinkingTagsFromStream(text: string): string {
  return removeThinkingTags(text);
}

/** 从模型原文构建写入酒馆的完整消息（含 sum / UpdateVariable） */
function buildFinalAssistantMessage(cleanedRaw: string): string {
  const cleaned = removeThinkingTags(cleanedRaw).trim();
  const maintext = parseMaintext(cleaned);
  const options = parseOptions(cleaned);
  const optionBlock =
    options.length > 0 ? options.map((o: StoryOption) => `${o.id}. ${o.text}`).join('\n') : '继续';
  let finalMessage = `<maintext>${maintext || '（暂无剧情文本）'}</maintext>\n\n<option>${optionBlock}</option>`;
  const sum = parseSum(cleaned);
  const uvMatches = [...cleaned.matchAll(/<UpdateVariable>([\s\S]*?)<\/UpdateVariable>/gi)];
  const updateInner = uvMatches.length ? (uvMatches[uvMatches.length - 1][1] ?? '').trim() : '';
  if (sum) finalMessage += `\n\n<sum>${sum}</sum>`;
  if (updateInner) finalMessage += `\n\n<UpdateVariable>${updateInner}</UpdateVariable>`;
  return finalMessage;
}

async function resolveAssistantLayerData(finalMessage: string): Promise<Record<string, unknown>> {
  const fallback = getMvuLayerPayloadFromLatestMessage();
  try {
    await waitGlobalInitialized('Mvu');
  } catch {
    return fallback as Record<string, unknown>;
  }
  if (typeof Mvu === 'undefined') {
    return fallback as Record<string, unknown>;
  }
  try {
    const base = Mvu.getMvuData({ type: 'message', message_id: 'latest' });
    const parsed = await Mvu.parseMessage(finalMessage, base);
    if (parsed && typeof parsed === 'object') {
      return parsed as unknown as Record<string, unknown>;
    }
  } catch (err) {
    console.warn('⚠️ [大泼猴] Mvu.parseMessage 失败', err);
  }
  return fallback as Record<string, unknown>;
}

function attachStreamingPreview(callbacks: StoryRequestCallbacks): EventOnReturn | null {
  if (!callbacks.onStreamingUpdate) return null;
  return eventOn(iframe_events.STREAM_TOKEN_RECEIVED_FULLY, (fullText: string) => {
    const cleanedText = removeThinkingTags(fullText);
    if (!cleanedText.trim()) return;
    const maintextMatch = cleanedText.match(/<maintext>([\s\S]*?)(?:<\/maintext>|$)/i);
    if (maintextMatch?.[1]) {
      callbacks.onStreamingUpdate?.(maintextMatch[1].trim());
    }
  });
}

async function rollbackFailedRequest(
  userMessageId: number | null,
  request: RequestData,
  prompt: string,
  callbacks: StoryRequestCallbacks,
) {
  if (userMessageId === null) return;
  try {
    await deleteChatMessages([userMessageId], { refresh: 'none' });
    callbacks.onRefreshStory?.();
  } catch (deleteError) {
    console.warn('⚠️ [大泼猴] 回滚用户楼层失败', deleteError);
  }
  if (request.type === 'custom') {
    callbacks.onRestoreUserInput?.(prompt);
  }
}

/**
 * 在聊天末尾已存在对应用户楼、且已删掉待替换的 AI 楼时调用：仅 generate + 校验 + MVU + 追加 assistant。
 */
export async function handleAssistantRegenerateOnly(
  userPrompt: string,
  callbacks: StoryRequestCallbacks,
): Promise<boolean> {
  callbacks.onDisableOptions?.();
  callbacks.onShowGenerating?.();
  const prompt = userPrompt.trim();
  if (!prompt) {
    callbacks.onHideGenerating?.();
    callbacks.onEnableOptions?.();
    callbacks.onError?.('用户消息为空，无法重 roll');
    return false;
  }

  let streamSub: EventOnReturn | null = null;
  try {
    streamSub = attachStreamingPreview(callbacks);

    const result = await generate({
      user_input: prompt,
      should_stream: true,
    });

    if (typeof result !== 'string') {
      throw new Error('模型未返回文本结果');
    }

    const regenFormat = validateGeneratedStoryFormat(result);
    if (!regenFormat.ok) {
      throw new Error(regenFormat.reason);
    }

    const finalMessage = buildFinalAssistantMessage(result);
    const assistantData = await resolveAssistantLayerData(finalMessage);

    await createChatMessages(
      [{ role: 'assistant', message: finalMessage, data: assistantData }],
      { refresh: 'none' },
    );
    const assistantMessageId = getLastMessageId();
    await checkAndUpdateChronicleByAssistantMessage(assistantMessageId);

    callbacks.onRefreshVariables?.();
    callbacks.onRefreshStory?.();
    callbacks.onHideGenerating?.();
    callbacks.onEnableOptions?.();
    return true;
  } catch (error) {
    console.error('❌ [大泼猴] 重 roll 失败', error);
    const message = error instanceof Error ? error.message : '请求失败';
    callbacks.onHideGenerating?.();
    callbacks.onEnableOptions?.();
    callbacks.onError?.(message);
    return false;
  } finally {
    streamSub?.stop();
  }
}

export async function handleUnifiedRequest(
  request: RequestData,
  callbacks: StoryRequestCallbacks,
): Promise<boolean> {
  let userMessageId: number | null = null;
  let streamSub: EventOnReturn | null = null;

  callbacks.onDisableOptions?.();
  callbacks.onShowGenerating?.();

  const prompt =
    request.type === 'option' ? request.content : request.content.trim();
  if (!prompt) {
    callbacks.onHideGenerating?.();
    callbacks.onEnableOptions?.();
    callbacks.onError?.('输入为空，无法请求');
    return false;
  }

  try {
    const userLayerData = getMvuLayerPayloadFromLatestMessage();
    await createChatMessages(
      [{ role: 'user', message: prompt, data: userLayerData as Record<string, unknown> }],
      { refresh: 'none' },
    );
    userMessageId = getLastMessageId();

    streamSub = attachStreamingPreview(callbacks);

    const result = await generate({
      user_input: prompt,
      should_stream: true,
    });

    if (typeof result !== 'string') {
      throw new Error('模型未返回文本结果');
    }

    const format = validateGeneratedStoryFormat(result);
    if (!format.ok) {
      await rollbackFailedRequest(userMessageId, request, prompt, callbacks);
      callbacks.onHideGenerating?.();
      callbacks.onEnableOptions?.();
      callbacks.onError?.(format.reason);
      return false;
    }

    const finalMessage = buildFinalAssistantMessage(result);
    const assistantData = await resolveAssistantLayerData(finalMessage);

    await createChatMessages(
      [{ role: 'assistant', message: finalMessage, data: assistantData }],
      { refresh: 'none' },
    );
    const assistantMessageId = getLastMessageId();
    await checkAndUpdateChronicleByAssistantMessage(assistantMessageId);

    callbacks.onRefreshVariables?.();
    callbacks.onHideGenerating?.();

    window.setTimeout(() => {
      callbacks.onRefreshStory?.();
    }, 300);

    callbacks.onEnableOptions?.();
    return true;
  } catch (error) {
    console.error('❌ [大泼猴] 请求处理失败', error);
    const message = error instanceof Error ? error.message : '请求失败';
    await rollbackFailedRequest(userMessageId, request, prompt, callbacks);
    callbacks.onHideGenerating?.();
    callbacks.onEnableOptions?.();
    callbacks.onError?.(message);
    return false;
  } finally {
    streamSub?.stop();
  }
}
