/**
 * 主界面右侧四栏：当前队伍 / 队伍详情 / 附近 NPC / 附近详情。
 * 数据来自 MVU `孙悟空.队伍`（或旧版 `世界.当前队伍`）、`世界.在场NPC` 与 `羁绊.*`；头像可本地持久化。
 */

import React from 'react';
import { Camera, MapPin, Users } from 'lucide-react';
import type { Bond } from '../types';
import { resolveBondDisplayAvatar } from '../utils/bondAvatar';

export function bondForNpcName(name: string, bonds: Bond[]): Bond {
  const b = bonds.find(x => x.id === name || x.name === name);
  if (b) return b;
  return {
    id: name,
    name,
    relation: '—',
    protagonistRelation: '',
    bio: '',
    favorability: 0,
    thought: '',
    realm: '',
  };
}

/** 持久化 / MVU / 内置默认图（见 `utils/bondAvatar.ts`）；均无则 null，格子显示姓名 */
function bondSpecifiedAvatarUrl(b: Bond, local: Record<string, string>): string | null {
  return resolveBondDisplayAvatar(b, local) ?? null;
}

export type NpcSideColumnProps = {
  partyNames: string[];
  nearbyNames: string[];
  bonds: Bond[];
  bondAvatarById: Record<string, string>;
  selectedTeamId: string | null;
  selectedNearbyId: string | null;
  onSelectTeam: (id: string) => void;
  onSelectNearby: (id: string) => void;
  onRequestBondAvatar: (bondId: string) => void;
};

function SectionLabel({ children }: { children: React.ReactNode }) {
  return (
    <div className="border-b border-gold/20 pb-1.5 mb-2">
      <span className="text-[9px] font-semibold uppercase tracking-[0.22em] text-gold/50">{children}</span>
    </div>
  );
}

/** 队伍 / 附近 NPC 头像列表：人数多时纵向滚动，与 oriental 滚动条样式一致 */
function NpcIconScrollList({ children }: { children: React.ReactNode }) {
  return (
    <div className="min-h-0 max-h-[min(220px,42vh)] overflow-y-auto overflow-x-hidden overscroll-y-contain pr-1 scrollbar-oriental">
      <div className="flex flex-wrap content-start gap-1.5">{children}</div>
    </div>
  );
}

function NpcIconButton({
  name,
  selected,
  onClick,
  avatarUrl,
}: {
  name: string;
  selected: boolean;
  onClick: () => void;
  avatarUrl: string | null;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      title={name}
      className={`relative w-[42px] shrink-0 aspect-[3/4] overflow-hidden rounded-md border transition-colors ${
        selected
          ? 'border-gold-bright shadow-[0_0_12px_rgba(212,175,55,0.45)]'
          : 'border-gold/30 hover:border-gold/60'
      }`}
    >
      {avatarUrl ? (
        <img src={avatarUrl} alt="" className="h-full w-full object-cover" loading="lazy" referrerPolicy="no-referrer" />
      ) : (
        <span className="flex h-full w-full items-center justify-center bg-ink/90 px-0.5 text-center text-[8px] font-medium leading-[1.15] text-gold/88 [word-break:break-word] line-clamp-4">
          {name}
        </span>
      )}
      <span className="sr-only">{name}</span>
    </button>
  );
}

function NpcDetailPanel({
  bond,
  bondAvatarById,
  variant,
  onRequestBondAvatar,
  emptyHint,
}: {
  bond: Bond | null;
  bondAvatarById: Record<string, string>;
  variant: 'team' | 'nearby';
  onRequestBondAvatar: (bondId: string) => void;
  emptyHint: string;
}) {
  if (!bond) {
    return (
      <div className="flex min-h-[120px] min-w-0 flex-1 items-center justify-center rounded-lg border border-gold/15 bg-black/40 px-2 py-4 text-center text-[11px] leading-relaxed text-gold/35">
        {emptyHint}
      </div>
    );
  }

  const avatarUrl = bondSpecifiedAvatarUrl(bond, bondAvatarById);
  const fav = Math.min(100, Math.max(0, bond.favorability));

  return (
    <div className="flex min-h-0 min-w-0 flex-1 flex-col overflow-hidden rounded-lg border border-gold/25 bg-black/55 shadow-[inset_0_1px_0_rgba(212,175,55,0.06)]">
      <div className="min-h-0 flex-1 overflow-y-auto px-2.5 py-3 scrollbar-oriental">
        <SectionLabel>肖像</SectionLabel>
        <div className="relative mx-auto mb-3 aspect-[3/4] max-h-[267px] w-[78%] min-w-[120px] max-w-[220px] overflow-hidden rounded border border-gold/35 bg-ink/80">
          {avatarUrl ? (
            <img src={avatarUrl} alt="" className="h-full w-full object-cover object-top" referrerPolicy="no-referrer" />
          ) : (
            <div className="flex h-full min-h-[176px] w-full items-center justify-center p-2 text-center font-display text-base leading-snug text-gold/80 [word-break:break-word]">
              {bond.name}
            </div>
          )}
          <button
            type="button"
            onClick={() => onRequestBondAvatar(bond.id)}
            className="absolute bottom-1.5 right-1.5 flex h-8 w-8 items-center justify-center rounded border border-gold/40 bg-black/75 text-gold/90 backdrop-blur-sm hover:border-gold hover:text-gold"
            title="更换头像（仅本次会话）"
            aria-label="更换头像"
          >
            <Camera size={16} strokeWidth={2.25} />
          </button>
        </div>

        <div className="mb-3 border-l-2 border-gold/40 pl-2">
          <h3 className="font-display text-lg tracking-wide text-gold-bright">{bond.name}</h3>
          <p className="mt-0.5 text-[11px] leading-snug text-gold/65">{bond.realm.trim() || '修为未录'}</p>
        </div>

        <SectionLabel>好感度</SectionLabel>
        <div className="mb-3">
          <div className="mb-1 flex justify-between text-[10px] text-gold/55">
            <span>FAVOR</span>
            <span className="tabular-nums">{fav} / 100</span>
          </div>
          <div className="h-2 overflow-hidden rounded-full border border-gold/20 bg-ink/80">
            <div
              className="h-full rounded-full bg-gradient-to-r from-crimson/80 to-gold/70 transition-[width] duration-300"
              style={{ width: `${fav}%` }}
            />
          </div>
        </div>

        <SectionLabel>对主角的看法</SectionLabel>
        <p className="mb-3 text-[11px] leading-relaxed text-gold/75">{bond.thought.trim() || '—'}</p>

        {variant === 'team' ? (
          <>
            <SectionLabel>与主角的关系</SectionLabel>
            <p className="mb-3 text-[11px] leading-relaxed text-gold/80">{bond.protagonistRelation.trim() || '—'}</p>
          </>
        ) : null}

        <SectionLabel>人物简介</SectionLabel>
        <p className="text-[11px] leading-relaxed text-gold/70 whitespace-pre-wrap">{bond.bio.trim() || '—'}</p>
      </div>
    </div>
  );
}

export function NpcSideColumn({
  partyNames,
  nearbyNames,
  bonds,
  bondAvatarById,
  selectedTeamId,
  selectedNearbyId,
  onSelectTeam,
  onSelectNearby,
  onRequestBondAvatar,
}: NpcSideColumnProps) {
  const teamBond = selectedTeamId ? bondForNpcName(selectedTeamId, bonds) : null;
  const nearbyBond = selectedNearbyId ? bondForNpcName(selectedNearbyId, bonds) : null;

  return (
    <aside
      className="dapohou-npc-hud z-[8] hidden min-h-0 w-[min(288px,24vw)] shrink-0 flex-col gap-2 self-stretch pl-1 pr-1 md:pr-2 xl:flex"
      aria-label="队伍与附近人物"
    >
      <section className="shrink-0 rounded-lg border border-gold/25 bg-ink/75 px-2 py-2 backdrop-blur-sm">
        <div className="mb-1.5 flex items-center gap-1.5 text-gold/70">
          <Users size={14} className="shrink-0 opacity-80" />
          <span className="text-[10px] font-medium tracking-wide">当前队伍</span>
        </div>
        <NpcIconScrollList>
          {partyNames.length === 0 ? (
            <span className="text-[10px] text-gold/35">
              MVU <code className="text-gold/45">孙悟空.队伍</code> 暂无
            </span>
          ) : (
            partyNames.map(n => {
              const b = bondForNpcName(n, bonds);
              return (
                <NpcIconButton
                  key={`party-${n}`}
                  name={n}
                  selected={selectedTeamId === n}
                  onClick={() => onSelectTeam(n)}
                  avatarUrl={bondSpecifiedAvatarUrl(b, bondAvatarById)}
                />
              );
            })
          )}
        </NpcIconScrollList>
      </section>

      <div className="flex min-h-[120px] flex-1 basis-0 flex-col overflow-hidden">
        <NpcDetailPanel
          bond={teamBond}
          bondAvatarById={bondAvatarById}
          variant="team"
          onRequestBondAvatar={onRequestBondAvatar}
          emptyHint="点击上方队伍头像查看详情（修为、看法、好感、关系与简介）。"
        />
      </div>

      <section className="shrink-0 rounded-lg border border-gold/25 bg-ink/75 px-2 py-2 backdrop-blur-sm">
        <div className="mb-1.5 flex items-center gap-1.5 text-gold/70">
          <MapPin size={14} className="shrink-0 opacity-80" />
          <span className="text-[10px] font-medium tracking-wide">附近 NPC</span>
        </div>
        <NpcIconScrollList>
          {nearbyNames.length === 0 ? (
            <span className="text-[10px] text-gold/35">MVU <code className="text-gold/45">世界.在场NPC</code> 暂无</span>
          ) : (
            nearbyNames.map(n => {
              const b = bondForNpcName(n, bonds);
              return (
                <NpcIconButton
                  key={`near-${n}`}
                  name={n}
                  selected={selectedNearbyId === n}
                  onClick={() => onSelectNearby(n)}
                  avatarUrl={bondSpecifiedAvatarUrl(b, bondAvatarById)}
                />
              );
            })
          )}
        </NpcIconScrollList>
      </section>

      <div className="flex min-h-[120px] flex-1 basis-0 flex-col overflow-hidden">
        <NpcDetailPanel
          bond={nearbyBond}
          bondAvatarById={bondAvatarById}
          variant="nearby"
          onRequestBondAvatar={onRequestBondAvatar}
          emptyHint="点击上方附近 NPC 查看详情（无「与主角的关系」一栏）。"
        />
      </div>
    </aside>
  );
}
