import type {
  Bond,
  Character,
  CultivationSkillUi,
  EquipmentSlotsState,
  Item,
  Quest,
  SpiritBeast,
  WorldMvuSlice,
} from '../types';

/** 从角色卡内置 MVU（消息楼层变量）的 `stat_data` 映射界面；优先识别 `孙悟空` 结构，并兼容旧版 `主角` / `大泼猴.主角`。 */

/** `孙悟空.功法.主修功法` 无有效名称时，修行面板「主修功法」展示用 */
export const MVU_TECHNIQUE_EMPTY_LABEL = '天机未开';

function coalesceNumber(value: unknown): number | undefined {
  if (typeof value === 'number' && !Number.isNaN(value)) return value;
  if (typeof value === 'string' && value.trim() !== '') {
    const n = Number(value);
    if (!Number.isNaN(n)) return n;
  }
  return undefined;
}

function asObject(value: unknown): Record<string, unknown> {
  if (value === null || value === undefined || typeof value !== 'object' || Array.isArray(value)) {
    return {};
  }
  return value as Record<string, unknown>;
}

/** Zod 根级 `孙悟空` 或 `大泼猴.孙悟空` */
export function getSunWukongBlock(statData: unknown): Record<string, unknown> {
  if (statData === null || statData === undefined || typeof statData !== 'object') {
    return {};
  }
  const root = statData as Record<string, unknown>;
  const direct = root['孙悟空'];
  if (direct && typeof direct === 'object' && !Array.isArray(direct)) {
    return direct as Record<string, unknown>;
  }
  const nested = root['大泼猴'];
  if (nested && typeof nested === 'object') {
    const sw = (nested as Record<string, unknown>)['孙悟空'];
    if (sw && typeof sw === 'object' && !Array.isArray(sw)) {
      return sw as Record<string, unknown>;
    }
  }
  return {};
}

/** 旧版扁平主角块：`主角` 或 `大泼猴.主角` */
function getLegacyPlayerBlock(statData: unknown): Record<string, unknown> {
  if (statData === null || statData === undefined || typeof statData !== 'object') {
    return {};
  }
  const root = statData as Record<string, unknown>;
  const nested = root['大泼猴'];
  if (nested && typeof nested === 'object') {
    const 主角 = (nested as Record<string, unknown>)['主角'];
    if (主角 && typeof 主角 === 'object') {
      return 主角 as Record<string, unknown>;
    }
  }
  const 主角 = root['主角'];
  if (主角 && typeof 主角 === 'object') {
    return 主角 as Record<string, unknown>;
  }
  return {};
}

function pickNumber(block: Record<string, unknown>, keys: string[]): number | undefined {
  for (const key of keys) {
    const v = coalesceNumber(_.get(block, key));
    if (v !== undefined) return v;
  }
  return undefined;
}

function pickString(block: Record<string, unknown>, keys: string[], fallback: string): string {
  for (const key of keys) {
    const v = _.get(block, key);
    if (typeof v === 'string' && v.trim().length > 0) return v.trim();
  }
  return fallback;
}

function pickStringArray(block: Record<string, unknown>, keys: string[], fallback: string[]): string[] {
  for (const key of keys) {
    const v = _.get(block, key);
    if (Array.isArray(v)) {
      const arr = v.map(x => String(x).trim()).filter(Boolean);
      if (arr.length > 0) return arr;
    }
    if (typeof v === 'string' && v.trim()) {
      return v
        .split(/[,，、]/)
        .map(s => s.trim())
        .filter(Boolean);
    }
  }
  return fallback;
}

/**
 * 从块中取字符串列表：按 keys 顺序，**第一个在对象上存在的键**决定结果（含空数组 / 空字符串 → []）；
 * 若所有键都不存在，返回 []。
 */
function pickStringListFromBlock(block: Record<string, unknown>, keys: string[]): string[] {
  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(block, key)) continue;
    const v = block[key];
    if (v === null || v === undefined) return [];
    if (Array.isArray(v)) return v.map(x => String(x).trim()).filter(Boolean);
    if (typeof v === 'string') {
      if (!v.trim()) return [];
      return v
        .split(/[,，、]/)
        .map(s => s.trim())
        .filter(Boolean);
    }
    return [];
  }
  return [];
}

/**
 * 用 MVU `stat_data` 合并主角展示。
 * - 若存在 `孙悟空`：读 `当前状态` / `能力面板` / `功法.主修功法` / `头像` / `修为境界` / `修为进度`
 * - 否则沿用旧扁平键（`主角` / `大泼猴.主角` 下的 hp、realm、…）
 */
export function mergeCharacterFromMvu(prev: Character, statData: unknown): Character {
  const swk = getSunWukongBlock(statData);
  const legacy = getLegacyPlayerBlock(statData);
  const next: Character = { ...prev };

  if (Object.keys(swk).length > 0) {
    const avatarUrl = pickString(swk, ['头像'], '');
    if (avatarUrl) next.avatar = avatarUrl;

    const cur = asObject(swk['当前状态']);
    const cap = asObject(swk['能力面板']);
    const gong = asObject(swk['功法']);
    const main = asObject(gong['主修功法']);

    const hp = coalesceNumber(cur['当前血量']);
    const maxHp = coalesceNumber(cap['最大血量']);
    const mp = coalesceNumber(cur['当前灵力']);
    const maxMp = coalesceNumber(cap['最大灵力']);
    const maxShou = coalesceNumber(cap['最大寿元']);

    if (hp !== undefined) next.hp = Math.max(0, hp);
    if (maxHp !== undefined && maxHp > 0) next.maxHp = maxHp;
    if (mp !== undefined) next.mp = Math.max(0, mp);
    if (maxMp !== undefined && maxMp > 0) next.maxMp = maxMp;
    if (maxShou !== undefined && maxShou >= 0) next.age = Math.floor(maxShou);

    const exp = coalesceNumber(swk['修为进度']);
    if (exp !== undefined) next.exp = Math.max(0, exp);
    if (next.maxExp <= 0) next.maxExp = 100;

    next.realm = pickString(swk, ['修为境界'], next.realm);

    const tName = pickString(main, ['名称'], '');
    const mainAv = pickString(main, ['头像'], '');
    if (tName && tName !== '无') {
      next.mainTechniqueName = tName;
      next.mainTechniqueMvuAvatar = mainAv || undefined;
      const parts = [
        tName,
        pickString(main, ['境界'], ''),
        pickString(main, ['品阶'], ''),
        pickString(main, ['特效'], ''),
      ].filter(s => s && s !== '无');
      next.technique = parts.length > 0 ? parts.join(' · ') : MVU_TECHNIQUE_EMPTY_LABEL;
    } else {
      next.mainTechniqueName = undefined;
      next.mainTechniqueMvuAvatar = undefined;
      next.technique = MVU_TECHNIQUE_EMPTY_LABEL;
    }

    const buffState = cur['增益状态'];
    if (buffState && typeof buffState === 'object' && !Array.isArray(buffState)) {
      const entries = Object.entries(buffState as Record<string, unknown>).filter(
        ([k]) => k && String(k).trim().length > 0,
      );
      if (entries.length > 0) {
        next.buffs = entries.map(([k, v]) => {
          const vs = typeof v === 'string' ? v.trim() : v != null && typeof v !== 'object' ? String(v) : '';
          return vs ? `${k}：${vs}` : k;
        });
      } else {
        next.buffs = pickStringListFromBlock(cur, ['增益', 'buffs']);
        if (next.buffs.length === 0) {
          next.buffs = pickStringListFromBlock(swk, ['增益', '增益状态', 'buffs']);
        }
      }
    } else {
      const fromCur = pickStringListFromBlock(cur, ['增益', '增益状态', 'buffs']);
      next.buffs = fromCur.length > 0 ? fromCur : pickStringListFromBlock(swk, ['增益', '增益状态', 'buffs']);
    }
    next.debuffs = pickStringListFromBlock(swk, ['异常状态', '异常', '减益', 'debuffs']);

    const spiritStones = pickNumber(swk, ['spiritStones', '灵石', 'spirit_stones']);
    const year = pickNumber(swk, ['year', '年']);
    const month = pickNumber(swk, ['month', '月']);
    if (spiritStones !== undefined && spiritStones >= 0) next.spiritStones = Math.floor(spiritStones);
    if (year !== undefined && year > 0) next.year = Math.floor(year);
    if (month !== undefined && month >= 1 && month <= 12) next.month = Math.floor(month);

    next.name = pickString(swk, ['name', '姓名', '名讳'], next.name);
    next.title = pickString(swk, ['title', '称号', '头衔'], next.title);
  } else {
    const p = legacy;

    const hp = pickNumber(p, ['hp', '生命', '气血', '气血值']);
    const maxHp = pickNumber(p, ['maxHp', 'max_hp', '生命上限', '气血上限', 'hpMax', 'hp_max']);
    const mp = pickNumber(p, ['mp', '灵力', '法力']);
    const maxMp = pickNumber(p, ['maxMp', 'max_mp', '灵力上限', '法力上限', 'mpMax']);
    const exp = pickNumber(p, ['exp', '修为', '修炼进度', '当前修为']);
    const maxExp = pickNumber(p, ['maxExp', 'max_exp', '本级所需', '修为上限', '升级所需']);
    const age = pickNumber(p, ['age', '寿元', '年龄']);
    const spiritStones = pickNumber(p, ['spiritStones', '灵石', 'spirit_stones']);
    const year = pickNumber(p, ['year', '年']);
    const month = pickNumber(p, ['month', '月']);

    if (hp !== undefined) next.hp = Math.max(0, hp);
    if (maxHp !== undefined && maxHp > 0) next.maxHp = maxHp;
    if (mp !== undefined) next.mp = Math.max(0, mp);
    if (maxMp !== undefined && maxMp > 0) next.maxMp = maxMp;
    if (exp !== undefined) next.exp = Math.max(0, exp);
    if (maxExp !== undefined && maxExp > 0) next.maxExp = maxExp;
    if (age !== undefined && age >= 0) next.age = Math.floor(age);
    if (spiritStones !== undefined && spiritStones >= 0) next.spiritStones = Math.floor(spiritStones);
    if (year !== undefined && year > 0) next.year = Math.floor(year);
    if (month !== undefined && month >= 1 && month <= 12) next.month = Math.floor(month);

    next.name = pickString(p, ['name', '姓名', '名讳'], next.name);
    next.title = pickString(p, ['title', '称号', '头衔'], next.title);
    next.realm = pickString(p, ['realm', '境界', '修为境界', '当前境界'], next.realm);
    next.technique = pickString(p, ['technique', '功法', '主修功法'], next.technique);
    if (!next.technique.trim() || next.technique === '无') {
      next.technique = MVU_TECHNIQUE_EMPTY_LABEL;
      next.mainTechniqueName = undefined;
      next.mainTechniqueMvuAvatar = undefined;
    } else {
      const raw = next.technique.trim();
      next.mainTechniqueName = raw.split(/\s*[·•]\s*/)[0]?.trim() || raw;
      next.mainTechniqueMvuAvatar = undefined;
    }
    next.buffs = pickStringListFromBlock(p, ['增益', '增益状态', 'buffs']);
    next.debuffs = pickStringListFromBlock(p, ['异常状态', '异常', '减益', 'debuffs']);
  }

  if (next.hp > next.maxHp) next.hp = next.maxHp;
  if (next.mp > next.maxMp) next.mp = next.maxMp;
  if (next.exp > next.maxExp) next.exp = next.maxExp;

  return next;
}

/** 根键优先，其次 `大泼猴.xxx`（与 Zod 顶层字段一致） */
function getListFromStatData(statData: unknown, leafKey: string): unknown {
  if (statData === null || statData === undefined || typeof statData !== 'object') {
    return undefined;
  }
  const root = statData as Record<string, unknown>;
  if (root[leafKey] !== undefined) return root[leafKey];
  const nested = root['大泼猴'];
  if (nested && typeof nested === 'object') {
    const leaf = (nested as Record<string, unknown>)[leafKey];
    if (leaf !== undefined) return leaf;
  }
  return undefined;
}

function normalizeIdRows(raw: unknown): Array<{ id: string; row: Record<string, unknown> }> {
  if (raw === undefined || raw === null) return [];
  if (Array.isArray(raw)) {
    return raw
      .map((x, i) => {
        if (x === null || typeof x !== 'object' || Array.isArray(x)) return null;
        const row = x as Record<string, unknown>;
        const id = pickString(row, ['id', 'ID'], String(i));
        return id.trim() ? { id: id.trim(), row } : null;
      })
      .filter((x): x is { id: string; row: Record<string, unknown> } => x !== null);
  }
  if (typeof raw === 'object') {
    return Object.entries(raw as Record<string, unknown>).map(([k, v]) => {
      if (v !== null && typeof v === 'object' && !Array.isArray(v)) {
        const row = v as Record<string, unknown>;
        const id = pickString(row, ['id', 'ID'], k);
        return { id: id.trim() || k, row };
      }
      return { id: k, row: { name: String(v) } };
    });
  }
  return [];
}

function clampFavor(n: number): number {
  return Math.min(100, Math.max(0, Math.round(n)));
}

function bondFromMvuRow(id: string, row: Record<string, unknown>): Bond {
  const fav = pickNumber(row, ['favorability', '好感', '好感度']);
  const mvuAv = pickString(row, ['头像'], '');
  const loc = pickString(row, ['所在位置', 'location'], '');
  const rel = pickString(row, ['relation'], '');
  const pr = pickString(row, ['与主角的关系', '主角关系', '关系', '羁绊关系'], '');
  return {
    id,
    name: pickString(row, ['name', '姓名', '名称'], id),
    relation: loc || rel || '—',
    protagonistRelation: pr,
    bio: pickString(row, ['人物简介', '简介', '传记', 'bio', 'description'], ''),
    favorability: fav !== undefined ? clampFavor(fav) : 0,
    thought: pickString(row, ['thought', '想法', '当前想法', '心思', '内心', '对主角的想法'], ''),
    realm: pickString(row, ['realm', '境界', '修为', '修为等级', '当前境界', '当前修为'], ''),
    mvuAvatar: mvuAv || undefined,
  };
}

function mergeBondRow(prev: Bond, row: Record<string, unknown>): Bond {
  const fav = pickNumber(row, ['favorability', '好感', '好感度']);
  const mvuAv = pickString(row, ['头像'], '');
  const loc = pickString(row, ['所在位置', 'location'], '');
  const relPick = pickString(row, ['relation'], '');
  const nextRelation = loc || relPick ? loc || relPick : prev.relation;
  return {
    ...prev,
    name: pickString(row, ['name', '姓名', '名称'], prev.name),
    relation: nextRelation,
    protagonistRelation: pickString(
      row,
      ['与主角的关系', '主角关系', '关系', '羁绊关系'],
      prev.protagonistRelation,
    ),
    bio: pickString(row, ['人物简介', '简介', '传记', 'bio', 'description'], prev.bio),
    favorability: fav !== undefined ? clampFavor(fav) : prev.favorability,
    thought: pickString(row, ['thought', '想法', '当前想法', '心思', '内心', '对主角的想法'], prev.thought),
    realm: pickString(row, ['realm', '境界', '修为', '修为等级', '当前境界', '当前修为'], prev.realm),
    mvuAvatar: mvuAv || prev.mvuAvatar,
  };
}

export function mergeBondsFromMvu(prev: Bond[], statData: unknown): Bond[] {
  const raw = getListFromStatData(statData, '羁绊');
  const entries = normalizeIdRows(raw);
  if (entries.length === 0) return prev;

  const map = new Map(prev.map(b => [b.id, { ...b }]));
  for (const { id, row } of entries) {
    const existing = map.get(id);
    if (existing) {
      map.set(id, mergeBondRow(existing, row));
    } else {
      map.set(id, bondFromMvuRow(id, row));
    }
  }

  const order = [...prev.map(b => b.id)];
  const extra = entries.map(e => e.id).filter(iid => !order.includes(iid));
  return [...order, ...extra].map(id => map.get(id)!).filter(Boolean);
}

function beastFromMvuRow(id: string, row: Record<string, unknown>): SpiritBeast {
  const status = pickString(row, ['状态', 'realm', '境界'], '');
  return {
    id,
    name: pickString(row, ['name', '姓名', '名称'], id),
    realm: status,
    ability: pickString(row, ['ability', '能力', '神通', '技能'], ''),
    description: pickString(row, ['description', '描述', '说明'], ''),
  };
}

function mergeSpiritRow(prev: SpiritBeast, row: Record<string, unknown>): SpiritBeast {
  const status = pickString(row, ['状态', 'realm', '境界'], prev.realm);
  return {
    ...prev,
    name: pickString(row, ['name', '姓名', '名称'], prev.name),
    realm: status,
    ability: pickString(row, ['ability', '能力', '神通', '技能'], prev.ability),
    description: pickString(row, ['description', '描述', '说明'], prev.description),
  };
}

/** `灵兽栏`（孙悟空 Schema）或旧键 `灵兽` */
export function mergeSpiritBeastsFromMvu(prev: SpiritBeast[], statData: unknown): SpiritBeast[] {
  const swk = getSunWukongBlock(statData);
  const fromBar = swk['灵兽栏'];
  const raw =
    fromBar !== undefined && fromBar !== null ? fromBar : getListFromStatData(statData, '灵兽');
  const entries = normalizeIdRows(raw);
  if (entries.length === 0) return prev;

  const map = new Map(prev.map(s => [s.id, { ...s }]));
  for (const { id, row } of entries) {
    const existing = map.get(id);
    if (existing) {
      map.set(id, mergeSpiritRow(existing, row));
    } else {
      map.set(id, beastFromMvuRow(id, row));
    }
  }

  const order = [...prev.map(s => s.id)];
  const extra = entries.map(e => e.id).filter(iid => !order.includes(iid));
  return [...order, ...extra].map(id => map.get(id)!).filter(Boolean);
}

function mapMvuItemType(s: string): Item['type'] {
  const t = s.trim();
  if (/武器|剑|刀|棍|棒|枪|戟/.test(t)) return 'weapon';
  if (/铠甲|护甲|甲|衣|袍|盔/.test(t)) return 'armor';
  if (/法宝|饰|戒|镯|珠|佩/.test(t)) return 'accessory';
  if (/丹|药|丹药|消耗|符/.test(t)) return 'pill';
  if (/装备/.test(t)) return 'weapon';
  return 'treasure';
}

/** 行囊条目 `类型`：与 Zod `enum(['装备','法宝','消耗品'])` 及旧版自由字符串兼容 */
function mapMvuItemTypeForInventory(类型: string, itemName: string): Item['type'] {
  const t = 类型.trim();
  if (t === '法宝') return 'accessory';
  if (t === '消耗品') return 'pill';
  if (t === '装备') {
    if (/铠|甲|衣|袍|盔|护/.test(itemName)) return 'armor';
    return 'weapon';
  }
  return mapMvuItemType(t || itemName);
}

function mapMvuRarity(s: string): Item['rarity'] {
  const t = s.toLowerCase();
  if (/传说|神话|仙品/.test(t)) return 'legendary';
  if (/史诗|稀世|玄品/.test(t)) return 'epic';
  if (/稀有|珍品|灵品/.test(t)) return 'rare';
  if (/优秀|良品|上品/.test(t)) return 'uncommon';
  return 'common';
}

/**
 * `孙悟空.行囊` → 行囊面板 Item[]。
 * - 存在 `孙悟空` 时：仅以变量中的 `行囊` 为准（缺省或空对象则清空列表）。
 * - 尚无 `孙悟空` 块时：保留 `prev`（兼容旧 stat_data）。
 */
export function mergeInventoryFromMvu(prev: Item[], statData: unknown): Item[] {
  const swk = getSunWukongBlock(statData);
  if (Object.keys(swk).length === 0) {
    return prev;
  }
  if (!('行囊' in swk)) {
    return [];
  }
  const bag = swk['行囊'];
  if (bag === null || typeof bag !== 'object' || Array.isArray(bag)) {
    return [];
  }
  const entries = Object.entries(bag as Record<string, unknown>);
  if (entries.length === 0) {
    return [];
  }

  const items = entries.map(([name, v]) => {
    const row = asObject(v);
    const qtyRaw = coalesceNumber(row['数量']);
    const qty = qtyRaw !== undefined ? Math.floor(qtyRaw) : 1;
    if (qty <= 0) return null;

    const desc = pickString(row, ['描述'], '');
    const shixiao = pickString(row, ['时效'], '');
    const qtyLabel = qty !== 1 ? `×${qty}` : '';
    const line = [qtyLabel, desc, shixiao && shixiao !== '永久' ? `时效：${shixiao}` : '']
      .filter(Boolean)
      .join(' · ');
    const safeId = `inv-${name.replace(/\s+/g, '_')}`.slice(0, 120);
    const mvuAvatar = pickString(row, ['头像'], '');
    return {
      id: safeId,
      name,
      type: mapMvuItemTypeForInventory(pickString(row, ['类型'], '消耗品'), name),
      rarity: mapMvuRarity(pickString(row, ['品阶'], '无')),
      description: line,
      quantity: qty,
      icon: `https://picsum.photos/seed/${encodeURIComponent(name.slice(0, 24))}/64/64`,
      ...(mvuAvatar ? { mvuAvatar } : {}),
    } satisfies Item;
  });
  return items.filter((x): x is Item => x !== null);
}

/** 根级 `当前任务`；地点优先读 `世界.当前地点`，否则用 `worldHint` */
export function mergeQuestsFromMvu(prev: Quest[], statData: unknown, worldHint: string): Quest[] {
  const raw = getListFromStatData(statData, '当前任务');
  if (raw === undefined || raw === null || typeof raw !== 'object' || Array.isArray(raw)) {
    return prev;
  }
  const entries = Object.entries(raw as Record<string, unknown>);
  if (entries.length === 0) return prev;

  const rawWorld = getListFromStatData(statData, '世界');
  let loc = worldHint;
  if (rawWorld && typeof rawWorld === 'object' && !Array.isArray(rawWorld)) {
    const p = (rawWorld as Record<string, unknown>)['当前地点'];
    if (typeof p === 'string' && p.trim()) loc = p.trim();
  }

  return entries.map(([title, v], i) => {
    const row = asObject(v);
    const goal = pickString(row, ['任务目标'], '');
    const reward = pickString(row, ['任务奖励'], '');
    const desc = [goal, reward].filter(Boolean).join('\n');
    return {
      id: `mvu-q-${i}-${title.replace(/\s/g, '_')}`.slice(0, 80),
      title,
      type: i === 0 ? 'main' : 'side',
      description: desc || '—',
      location: loc || '—',
      status: 'active',
    } satisfies Quest;
  });
}

/** 根级 `世界`；随队名单优先 `孙悟空.队伍`，其次兼容 `世界.当前队伍` */
export function mergeWorldFromMvu(prev: WorldMvuSlice, statData: unknown): WorldMvuSlice {
  const swk = getSunWukongBlock(statData);

  let party = prev.partyPresent;
  const raw = getListFromStatData(statData, '世界');
  const o =
    raw !== undefined && raw !== null && typeof raw === 'object' && !Array.isArray(raw)
      ? (raw as Record<string, unknown>)
      : null;

  if (o && Array.isArray(o['当前队伍'])) {
    const p = o['当前队伍'].map(x => String(x).trim()).filter(Boolean);
    if (p.length > 0) party = p;
  }

  if (Object.keys(swk).length > 0 && Object.prototype.hasOwnProperty.call(swk, '队伍')) {
    const arr = swk['队伍'];
    if (Array.isArray(arr)) {
      party = arr.map(x => String(x).trim()).filter(Boolean);
    }
  }

  if (!o) {
    return {
      ...prev,
      partyPresent: party,
    };
  }

  const place = typeof o['当前地点'] === 'string' ? String(o['当前地点']).trim() : prev.currentPlace;
  let npcs = prev.npcsPresent;
  if (Array.isArray(o['在场NPC'])) {
    const n = o['在场NPC'].map(x => String(x).trim()).filter(Boolean);
    if (n.length > 0) npcs = n;
  }

  const regionRaw = o['当前大区'];
  const region =
    typeof regionRaw === 'string' && regionRaw.trim()
      ? regionRaw.trim()
      : prev.currentRegion;

  return {
    currentPlace: place || prev.currentPlace,
    currentRegion: region || prev.currentRegion,
    npcsPresent: npcs,
    partyPresent: party,
  };
}

function itemFromArmorBlock(armorRaw: unknown): Item | null {
  if (typeof armorRaw === 'string') {
    const armorStr = armorRaw.trim();
    if (!armorStr || armorStr === '无') return null;
    return {
      id: 'mvu-slot-armor',
      name: armorStr,
      type: 'armor',
      rarity: 'common',
      description: '',
      icon: 'https://picsum.photos/seed/mvu-armor/64/64',
    };
  }
  if (!armorRaw || typeof armorRaw !== 'object' || Array.isArray(armorRaw)) return null;
  const row = asObject(armorRaw);
  const name = pickString(row, ['名称'], '');
  if (!name || name === '无') return null;
  const tier = pickString(row, ['品阶'], '无');
  return {
    id: 'mvu-slot-armor',
    name,
    type: 'armor',
    rarity: mapMvuRarity(tier),
    description: tier && tier !== '无' ? tier : '',
    icon: 'https://picsum.photos/seed/mvu-armor/64/64',
  };
}

function itemFromFabaoSlot(slotId: 'fabao1' | 'fabao2' | 'fabao3', rowRaw: unknown): Item | null {
  if (!rowRaw || typeof rowRaw !== 'object' || Array.isArray(rowRaw)) return null;
  const row = asObject(rowRaw);
  const name = pickString(row, ['名称'], '');
  if (!name || name === '无') return null;
  const tier = pickString(row, ['品阶'], '无');
  const fx = pickString(row, ['特效'], '');
  const parts = [tier && tier !== '无' ? `品阶：${tier}` : '', fx && fx !== '无' ? `特效：${fx}` : ''].filter(
    Boolean,
  );
  return {
    id: `mvu-slot-${slotId}`,
    name,
    type: 'accessory',
    rarity: mapMvuRarity(tier),
    description: parts.join(' · '),
    icon: `https://picsum.photos/seed/mvu-${slotId}/64/64`,
  };
}

/** `孙悟空.装备栏` → 铠甲 + 三个法宝槽（兼容旧版：字符串护甲/法宝、武器对象） */
export function mergeEquipmentSlotsFromMvu(prev: EquipmentSlotsState, statData: unknown): EquipmentSlotsState {
  const swk = getSunWukongBlock(statData);
  const eq = swk['装备栏'];
  if (eq === undefined || eq === null || typeof eq !== 'object' || Array.isArray(eq)) {
    return prev;
  }
  const o = eq as Record<string, unknown>;

  const armor = itemFromArmorBlock(o['护甲']);

  let fabao1: Item | null = null;
  let fabao2: Item | null = null;
  let fabao3: Item | null = null;
  const fabaoRaw = o['法宝'];
  if (typeof fabaoRaw === 'string') {
    const s = fabaoRaw.trim();
    fabao1 =
      s && s !== '无'
        ? {
            id: 'mvu-slot-fabao1',
            name: s,
            type: 'accessory',
            rarity: 'rare',
            description: '',
            icon: 'https://picsum.photos/seed/mvu-fabao1/64/64',
          }
        : null;
  } else if (fabaoRaw && typeof fabaoRaw === 'object' && !Array.isArray(fabaoRaw)) {
    const f = fabaoRaw as Record<string, unknown>;
    fabao1 = itemFromFabaoSlot('fabao1', f['槽位一']);
    fabao2 = itemFromFabaoSlot('fabao2', f['槽位二']);
    fabao3 = itemFromFabaoSlot('fabao3', f['槽位三']);
  }

  return { armor, fabao1, fabao2, fabao3 };
}

/**
 * `孙悟空.技能列表` → 修炼面板技能列表。
 * 存在 `孙悟空` 时仅以变量为准：缺 `技能列表` 或为空则清空占位。
 */
export function mergeSkillsFromMvu(prev: CultivationSkillUi[], statData: unknown): CultivationSkillUi[] {
  const swk = getSunWukongBlock(statData);
  if (Object.keys(swk).length === 0) {
    return prev;
  }
  if (!('技能列表' in swk)) {
    return [];
  }
  const skills = swk['技能列表'];
  if (skills === null || typeof skills !== 'object' || Array.isArray(skills)) {
    return [];
  }
  const entries = Object.entries(skills as Record<string, unknown>);
  if (entries.length === 0) {
    return [];
  }

  return entries.map(([name, v], i) => {
    const row = asObject(v);
    const desc = pickString(row, ['描述'], '');
    const prof = pickString(row, ['熟练度'], '初学乍练');
    const mvuAv = pickString(row, ['头像'], '');
    const body = [desc, `熟练度：${prof}`].filter(Boolean).join('\n');
    return {
      id: `mvu-skill-${i}-${name.replace(/\s/g, '_')}`.slice(0, 80),
      name,
      ...(mvuAv ? { mvuAvatar: mvuAv } : {}),
      level: 1,
      maxLevel: 9,
      type: '神通',
      cost: 0,
      cooldown: '—',
      description: body || '—',
    };
  });
}

/**
 * 读取 MVU 时应使用 **最新消息楼层** 的 `stat_data`（与 AI 更新变量后的状态一致）。
 * 在 iframe 内若仍用 `getCurrentMessageId()` 会钉死旧楼，故统一用 `'latest'`。
 */
export function getMvuMessageIdForLatestStatData(): 'latest' {
  return 'latest';
}
