/**
 * 开局表单：收集称呼与备注，提交后由 App 调用 gameInitializer 写入变量并生成首条剧情楼。
 */

import { useState, type FormEvent } from 'react';
import type { OpeningFormData } from '../types';

type OpeningFormProps = {
  onSubmit: (data: OpeningFormData) => void | Promise<void>;
  onBack?: () => void;
};

export default function OpeningForm({ onSubmit, onBack }: OpeningFormProps) {
  const [displayName, setDisplayName] = useState('');
  const [note, setNote] = useState('');
  const [busy, setBusy] = useState(false);

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    if (!displayName.trim()) {
      toastr.warning('请填写称呼', '大泼猴');
      return;
    }
    setBusy(true);
    try {
      await onSubmit({ displayName: displayName.trim(), note: note.trim() || undefined });
    } finally {
      setBusy(false);
    }
  };

  return (
    <div className="fade-in flex min-h-[100dvh] w-full flex-col items-center justify-center px-4 py-10">
      <div className="glass-panel scale-in w-full max-w-md p-6 md:p-8">
        <h2 className="mb-2 text-center text-xl tracking-[0.3em] text-gold md:text-2xl">开局</h2>
        <p className="mb-6 text-center text-xs text-gold/45">将写入本聊天变量，并生成首条 AI 剧情楼层。</p>
        <form onSubmit={handleSubmit} className="space-y-5">
          <div className="text-left">
            <label htmlFor="dapohou-display-name" className="mb-1 block text-[11px] uppercase tracking-widest text-gold/50">
              称呼
            </label>
            <input
              id="dapohou-display-name"
              type="text"
              value={displayName}
              onChange={e => setDisplayName(e.target.value)}
              placeholder="例如：行者、悟空"
              autoComplete="off"
              className="glass-card w-full rounded-lg border-gold/25 px-4 py-2.5 text-sm text-paper placeholder:text-gold/25 focus:border-gold/50 focus:outline-none"
            />
          </div>
          <div className="text-left">
            <label htmlFor="dapohou-note" className="mb-1 block text-[11px] uppercase tracking-widest text-gold/50">
              备注（可选）
            </label>
            <textarea
              id="dapohou-note"
              value={note}
              onChange={e => setNote(e.target.value)}
              placeholder="风格、难度、想强调的剧情方向…"
              rows={3}
              className="glass-card w-full resize-none rounded-lg border-gold/25 px-4 py-2.5 text-sm text-paper placeholder:text-gold/25 focus:border-gold/50 focus:outline-none"
            />
          </div>
          <div className="flex flex-wrap gap-3 pt-2">
            {onBack ? (
              <button
                type="button"
                onClick={onBack}
                disabled={busy}
                className="flex-1 rounded-lg border border-gold/30 py-2.5 text-xs text-gold/80 transition hover:border-gold/60 hover:text-gold disabled:opacity-50"
              >
                返回
              </button>
            ) : null}
            <button
              type="submit"
              disabled={busy}
              className="min-w-[8rem] flex-1 rounded-lg border border-gold/45 bg-gold/15 py-2.5 text-xs font-medium tracking-widest text-gold-bright transition hover:bg-gold/25 disabled:opacity-50"
            >
              {busy ? '处理中…' : '确认开局'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
