/**
 * 游戏初始化：界面默认面板快照；与 MVU 合并搭配使用。
 * 实际运行时以消息楼层 `stat_data`（见 variables/mvuStatSchemaTypes.ts）为准。
 *
 * `initializeGameVariables` / `createOpeningStoryMessage`：空聊天时由 App 阶段调用，写入开局数据与首条 assistant 楼层。
 */

import type {
  Bond,
  Character,
  CultivationSkillUi,
  EquipmentSlotsState,
  Item,
  OpeningFormData,
  Quest,
  SpiritBeast,
  WorldMvuSlice,
} from '../types';
import {
  initialBonds,
  initialCharacter,
  initialInventory,
  initialQuests,
  initialSpiritBeasts,
} from '../mockData';
import {
  mergeBondsFromMvu,
  mergeCharacterFromMvu,
  mergeEquipmentSlotsFromMvu,
  mergeInventoryFromMvu,
  mergeQuestsFromMvu,
  mergeSkillsFromMvu,
  mergeSpiritBeastsFromMvu,
  mergeWorldFromMvu,
} from './mvuCharacter';
import { getMvuLayerPayloadFromLatestMessage } from './variableReader';

/** 聊天变量中存放开局表单的键（与角色卡 Schema 无关，仅前端/调试可读） */
export const OPENING_CHAT_VAR_KEY = '大泼猴开局';

/**
 * 是否应显示「标题 / 开局」流程：无楼层，或仅有异常空楼层。
 */
export function isChatEmptyForOpening(): boolean {
  try {
    const lastId = getLastMessageId();
    if (lastId < 0) return true;
    if (lastId === 0) {
      try {
        const rows = getChatMessages(0, { hide_state: 'all' });
        return !rows?.length;
      } catch {
        return true;
      }
    }
    return false;
  } catch {
    return true;
  }
}

/**
 * 将开局表单写入聊天变量（并尽量保留原有 chat 键）。
 */
export async function initializeGameVariables(formData: OpeningFormData): Promise<boolean> {
  try {
    const chatVariables = getVariables({ type: 'chat' }) as Record<string, unknown>;
    replaceVariables(
      {
        ...chatVariables,
        [OPENING_CHAT_VAR_KEY]: {
          displayName: formData.displayName.trim(),
          note: (formData.note ?? '').trim(),
          submittedAt: Date.now(),
        },
      },
      { type: 'chat' },
    );
    return true;
  } catch (error) {
    console.error('❌ [大泼猴] initializeGameVariables 失败', error);
    return false;
  }
}

/**
 * 在空聊天末尾创建一条开局 assistant 楼层（含 &lt;maintext&gt; / &lt;option&gt;）。
 */
export async function createOpeningStoryMessage(formData: OpeningFormData): Promise<boolean> {
  try {
    const name = formData.displayName.trim() || '行者';
    const note = (formData.note ?? '').trim();
    const body = [
      `花果山巅，风起云涌。${name}，你自石中而来，天地间独一份灵明。`,
      note ? `\n\n（你的备注：${note}）` : '',
      '\n\n劫数已动，且看你如何走过这一程。',
    ].join('');
    const message = `<maintext>${body.trim()}</maintext>\n\n<option>继续</option>`;
    const data = getMvuLayerPayloadFromLatestMessage();
    await createChatMessages(
      [{ role: 'assistant', message, data: data as Record<string, unknown> }],
      { refresh: 'affected' },
    );
    return true;
  } catch (error) {
    console.error('❌ [大泼猴] createOpeningStoryMessage 失败', error);
    return false;
  }
}

/** 与 App 初始 state 对齐的可合并快照（用于测试或单次批量同步） */
export interface UiPanelsSnapshot {
  character: Character;
  world: WorldMvuSlice;
  bonds: Bond[];
  spiritBeasts: SpiritBeast[];
  inventory: Item[];
  equipment: EquipmentSlotsState;
  skills: CultivationSkillUi[];
  quests: Quest[];
}

export function getInitialUiPanelsSnapshot(): UiPanelsSnapshot {
  return {
    character: initialCharacter,
    world: {
      currentPlace: '黑风山 - 山脚',
      currentRegion: '未知',
      npcsPresent: [],
      partyPresent: [],
    },
    bonds: initialBonds,
    spiritBeasts: initialSpiritBeasts,
    inventory: initialInventory,
    equipment: { armor: null, fabao1: null, fabao2: null, fabao3: null },
    skills: [],
    quests: initialQuests,
  };
}

/**
 * 将 `stat_data` 一次性合并进快照（顺序与 App 内 pullMvu 一致）。
 * @param worldHint 任务面板地点兜底；通常传 `''`，由 mergeQuests 从 `世界.当前地点` 读取
 */
export function applyStatDataToPanelsSnapshot(
  prev: UiPanelsSnapshot,
  statData: unknown,
  worldHint = '',
): UiPanelsSnapshot {
  return {
    character: mergeCharacterFromMvu(prev.character, statData),
    world: mergeWorldFromMvu(prev.world, statData),
    bonds: mergeBondsFromMvu(prev.bonds, statData),
    spiritBeasts: mergeSpiritBeastsFromMvu(prev.spiritBeasts, statData),
    inventory: mergeInventoryFromMvu(prev.inventory, statData),
    equipment: mergeEquipmentSlotsFromMvu(prev.equipment, statData),
    skills: mergeSkillsFromMvu(prev.skills, statData),
    quests: mergeQuestsFromMvu(prev.quests, statData, worldHint),
  };
}
