/**
 * 标题界面：空聊天进入游戏前展示，点击进入开局表单。
 */

type TitleScreenProps = {
  onStart: () => void;
};

export default function TitleScreen({ onStart }: TitleScreenProps) {
  return (
    <div className="fade-in flex min-h-[100dvh] w-full flex-col items-center justify-center gap-10 px-6 py-12 text-center">
      <div className="slide-in-down space-y-4">
        <h1 className="text-5xl text-gold-bright md:text-6xl">大泼猴</h1>
        <p className="max-w-md text-sm leading-relaxed text-gold/55 md:text-base">
          劫数如潮，一念西行。若为新开一局，请先确认当前聊天无历史楼层。
        </p>
      </div>
      <button
        type="button"
        onClick={onStart}
        className="interactive glass-card border-2 border-gold/50 px-10 py-3 text-sm font-medium tracking-[0.35em] text-gold shadow-[0_0_24px_rgba(212,175,55,0.25)] adv-transition-colors hover:border-gold hover:bg-gold/10 hover:text-gold-bright"
      >
        踏入劫数
      </button>
    </div>
  );
}
