import { removeThinkingTags } from './messageParser';

type ChronicleRecord = {
  no: number;
  text: string;
};

function toChronicleNo(messageId: number): number {
  // 与 adventure 对齐：Math.floor(楼层号 / 2) + 1
  return Math.max(1, Math.floor(messageId / 2) + 1);
}

function parseChronicleContent(content: string): ChronicleRecord[] {
  const rows: ChronicleRecord[] = [];
  const lines = content
    .split('\n')
    .map(line => line.trim())
    .filter(Boolean);

  for (const line of lines) {
    const m1 = line.match(/^【\s*(\d+)\s*】\s*(.+)$/);
    if (m1) {
      rows.push({ no: Number(m1[1]), text: m1[2].trim() });
      continue;
    }
    const m2 = line.match(/^(\d+)[\.\):：、\s-]+\s*(.+)$/);
    if (m2) {
      rows.push({ no: Number(m2[1]), text: m2[2].trim() });
    }
  }

  // 去重：保留靠后的版本（更接近最新状态）
  const map = new Map<number, string>();
  for (const row of rows) {
    if (row.no > 0 && row.text) map.set(row.no, row.text);
  }
  return [...map.entries()].map(([no, text]) => ({ no, text }));
}

function formatChronicleContent(rows: ChronicleRecord[]): string {
  return rows
    .sort((a, b) => b.no - a.no)
    .map(row => `【${row.no}】 ${row.text}`)
    .join('\n');
}

async function getBoundWorldbooks(): Promise<string[]> {
  const names: string[] = [];
  try {
    const charBooks = getCharWorldbookNames('current');
    if (charBooks.primary) names.push(charBooks.primary);
    names.push(...(charBooks.additional ?? []));
  } catch (error) {
    console.warn('⚠️ [大泼猴] 获取角色绑定世界书失败', error);
  }
  return [...new Set(names.filter(Boolean))];
}

async function findChronicleEntry(): Promise<{
  worldbookName: string;
  worldbook: WorldbookEntry[];
  entry: WorldbookEntry;
} | null> {
  const bound = await getBoundWorldbooks();
  for (const wbName of bound) {
    try {
      const worldbook = await getWorldbook(wbName);
      const entry = worldbook.find(e => e.name === '编年史');
      if (entry) return { worldbookName: wbName, worldbook, entry };
    } catch (error) {
      console.warn(`⚠️ [大泼猴] 读取世界书失败: ${wbName}`, error);
    }
  }
  return null;
}

function parseSum(message: string): { sum: string; hasUnclosedSumTag: boolean } | null {
  const raw = message ?? '';
  const cleaned = removeThinkingTags(raw);

  // 若存在未闭合的 <sum> 标签（开启数 > 关闭数），按要求忽略该消息的 sum
  const openCount = (cleaned.match(/<sum\b/gi) ?? []).length;
  const closeCount = (cleaned.match(/<\/sum>/gi) ?? []).length;
  const hasUnclosedSumTag = openCount > closeCount;
  if (hasUnclosedSumTag) return null;

  const matches = [...cleaned.matchAll(/<sum>([\s\S]*?)<\/sum>/gi)];
  if (!matches.length) return null;

  const last = matches[matches.length - 1]?.[1]?.trim() ?? '';
  if (!last) return null;

  // 清理注释（便于编年史展示干净）
  const noComments = last.replace(/<!--[\s\S]*?-->/g, '').trim();
  if (!noComments) return null;

  return { sum: noComments, hasUnclosedSumTag: false };
}

function updateChronicleEntry(
  records: ChronicleRecord[],
  entryNo: number,
  entryText: string,
): ChronicleRecord[] {
  const has = records.some(r => r.no === entryNo);
  if (has) {
    return records.map(r => (r.no === entryNo ? { ...r, text: entryText } : r));
  }
  return [...records, { no: entryNo, text: entryText }];
}

export async function clearChronicleEntriesFromCurrentFloor(currentFloorMessageId: number): Promise<void> {
  try {
    const result = await findChronicleEntry();
    if (!result) {
      console.warn('⚠️ [大泼猴] clearChronicleEntriesFromCurrentFloor：未找到“编年史”条目');
      return;
    }
    const { worldbookName, worldbook, entry } = result;

    const currentNo = toChronicleNo(currentFloorMessageId);
    const records = parseChronicleContent(entry.content || '');

    const nextRecords = records.filter(r => r.no === 1 || r.no < currentNo);
    const nextContent = formatChronicleContent(nextRecords);
    if (nextContent === (entry.content || '').trim()) return;

    const nextWorldbook = worldbook.map(wbEntry => (wbEntry.uid !== entry.uid ? wbEntry : { ...wbEntry, content: nextContent }));
    await replaceWorldbook(worldbookName, nextWorldbook, { render: 'debounced' });
    console.info(`✅ [大泼猴] 编年史已清理（≥${currentNo}）：世界书=${worldbookName}`);
  } catch (error) {
    console.error('❌ [大泼猴] clearChronicleEntriesFromCurrentFloor 失败', error);
  }
}

async function updateChronicleInWorldbook(currentFloorMessageId: number, sumText: string): Promise<void> {
  const result = await findChronicleEntry();
  if (!result) {
    console.warn('⚠️ [大泼猴] updateChronicleInWorldbook：未在当前角色绑定世界书中找到“编年史”条目');
    return;
  }

  const { worldbookName, worldbook, entry } = result;

  const currentNo = toChronicleNo(currentFloorMessageId);
  const records = parseChronicleContent(entry.content || '');
  const hasCurrent = records.some(r => r.no === currentNo);
  const hasHigher = records.some(r => r.no > currentNo);

  let nextRecords = records;

  // 读档处理：清空编号 >= 当前条目编号，但保留条目 1
  if (hasHigher) {
    nextRecords = nextRecords.filter(r => r.no === 1 || r.no < currentNo);
  }

  // 重 roll / 正常更新：替换或添加当前编号条目
  nextRecords = updateChronicleEntry(nextRecords, currentNo, sumText);

  const nextContent = formatChronicleContent(nextRecords);
  if (nextContent === (entry.content || '').trim()) return;

  const nextWorldbook = worldbook.map(wbEntry => {
    if (wbEntry.uid !== entry.uid) return wbEntry;
    return { ...wbEntry, content: nextContent };
  });

  await replaceWorldbook(worldbookName, nextWorldbook, { render: 'debounced' });
  console.info(
    `✅ [大泼猴] 编年史已更新：世界书=${worldbookName}，编号=${currentNo}（hasCurrent=${hasCurrent} hasHigher=${hasHigher}）`,
  );
}

function findLatestSumMessage(startMessageId: number): { messageId: number; sumText: string } | null {
  try {
    if (startMessageId < 0) return null;

    // 只拉 assistant，避免 user/system 污染解析
    const assistantMessages = getChatMessages(`0-${startMessageId}`, { role: 'assistant', hide_state: 'all' }) ?? [];
    if (!assistantMessages.length) return null;

    for (let i = assistantMessages.length - 1; i >= 0; i--) {
      const m = assistantMessages[i];
      const mid = m?.message_id as number | undefined;
      if (typeof mid !== 'number') continue;
      if (mid > startMessageId) continue;
      const parsed = parseSum(m.message || '');
      if (parsed?.sum) return { messageId: mid, sumText: parsed.sum };
    }
  } catch (error) {
    console.error('❌ [大泼猴] findLatestSumMessage 失败', error);
  }
  return null;
}

export async function checkAndUpdateChronicle(): Promise<void> {
  try {
    const startId = getLastMessageId();
    if (startId < 0) return;

    console.info(`🔍 [大泼猴] checkAndUpdateChronicle：从最新楼层 #${startId} 向下查找 <sum>`);
    const found = findLatestSumMessage(startId);
    if (!found) {
      console.warn('⚠️ [大泼猴] checkAndUpdateChronicle：未找到包含 <sum> 的消息');
      return;
    }

    await updateChronicleInWorldbook(found.messageId, found.sumText);
  } catch (error) {
    console.error('❌ [大泼猴] checkAndUpdateChronicle 失败', error);
  }
}

// 向下兼容：旧入口仍保留，但内部改为新逻辑（支持重 roll / 读档清理）。
export async function checkAndUpdateChronicleByAssistantMessage(assistantMessageId: number): Promise<void> {
  if (assistantMessageId < 0) return;
  try {
    const assistantRows = getChatMessages(assistantMessageId, { role: 'assistant', hide_state: 'all' });
    const assistantMessage = assistantRows[0]?.message ?? '';
    const parsed = parseSum(assistantMessage);
    if (!parsed?.sum) return;
    await updateChronicleInWorldbook(assistantMessageId, parsed.sum);
  } catch (error) {
    console.error('❌ [大泼猴] checkAndUpdateChronicleByAssistantMessage 失败', error);
  }
}

